137			branch := wt.Branch
138			if branch == "" {
139				branch, _ = git.CurrentBranchIn(wt.Path)
140			}
141	
142			isCurrent := wt.Path == cwd || isSubpath(cwd, wt.Path)
143	
144			info := worktreeInfo{
145				Path:      wt.Path,
146				ShortName: short,
147				Branch:    branch,
148				IsCurrent: isCurrent,
149			}
150	
151			// Dirty count for all worktrees
152			if changes, err := git.StatusPorcelainIn(wt.Path); err == nil {
153				info.DirtyCount = len(changes)
154			}
155	
156			if !ctx.isBaseBranch(branch) {
157				info.Age = git.LastCommitAge(wt.Path)
158				ab, err := git.GetAheadBehindIn(wt.Path, ctx.baseRef())
159				if err == nil {
160					info.Behind = ab.Behind
161					info.Ahead = ab.Ahead
162				}
163				featureBranches = append(featureBranches, branch)
164			}
165	
166			infos = append(infos, info)
167		}
168	
169		return infos, featureBranches
170	}
171	
172	// fetchPRData fetches open, merged, and closed PRs in parallel.
173	func fetchPRData() (openPRs, mergedPRs, closedPRs []github.PR, hasErrors bool) {
174		var openErr, mergedErr, closedErr error
175		var wg sync.WaitGroup
176		wg.Add(3)
177		go func() { defer wg.Done(); openPRs, openErr = github.ListPRs("open") }()
178		go func() { defer wg.Done(); mergedPRs, mergedErr = github.ListPRs("merged") }()
179		go func() { defer wg.Done(); closedPRs, closedErr = github.ListPRs("closed") }()
180		wg.Wait()
181		hasErrors = openErr != nil || mergedErr != nil || closedErr != nil
182		return
183	}
184	
185	func runListJSON(ctx *cmdContext, cwd string, worktrees []git.Worktree) error {
186		infos, _ := collectWorktreeInfos(ctx, cwd, worktrees)
187	
188		// Fetch PR data (no spinner, no terminal output)
189		var openPRs, mergedPRs, closedPRs []github.PR
190		if github.IsAvailable() {
191			openPRs, mergedPRs, closedPRs, _ = fetchPRData()
192		}
193	
194		entries := make([]listJSONEntry, 0, len(infos))
195		hasBehind := false
196		hasStale := false
197		for _, info := range infos {
198			isBase := ctx.isBaseBranch(info.Branch)
199	
200			entry := listJSONEntry{
201				Name:       info.ShortName,
202				Path:       info.Path,
203				Branch:     info.Branch,
204				Current:    info.IsCurrent,
205				BaseBranch: isBase,
206				Age:        info.Age,
207				Dirty:      info.DirtyCount,
208				Behind:     info.Behind,
209				Ahead:      info.Ahead,
210			}
211	
212			if !isBase {
213				entry.PR = findPRJSON(info.Branch, openPRs, mergedPRs, closedPRs)
214				if info.Behind > 0 {
215					hasBehind = true
216				}
217				if entry.PR != nil && (entry.PR.State == "merged" || entry.PR.State == "closed") {
218					hasStale = true
219				}
220			}
221	
222			entries = append(entries, entry)
223		}
224	
225		data, err := json.MarshalIndent(listJSONOutput{Worktrees: entries, CTA: deriveListCTA(hasStale, hasBehind)}, "", "  ")
226		if err != nil {
227			return err
228		}
229		fmt.Println(string(data))
230		return nil
231	}
