233	func runListTOON(ctx *cmdContext, cwd string, worktrees []git.Worktree) error {
234		infos, _ := collectWorktreeInfos(ctx, cwd, worktrees)
235	
236		var openPRs, mergedPRs, closedPRs []github.PR
237		if github.IsAvailable() {
238			openPRs, mergedPRs, closedPRs, _ = fetchPRData()
239		}
240	
241		hasBehind := false
242		hasStale := false
243	
244		fmt.Println("worktrees:")
245		for _, info := range infos {
