269						fmt.Printf("  pr.review: %d✓ %d✗ %d●\n", pr.Review.Approved, pr.Review.Changes, pr.Review.Pending)
270						fmt.Printf("  pr.ci: %d✓ %d✗ %d● / %d\n", pr.CI.Pass, pr.CI.Fail, pr.CI.Pending, pr.CI.Total)
271					}
272					if pr.State == "merged" || pr.State == "closed" {
273						hasStale = true
