283	// deriveListCTA returns CTA suggestions based on worktree state.
284	func deriveListCTA(hasStale, hasBehind bool) []string {
285		if hasStale {
286			return []string{"wt prune"}
287		}
288		if hasBehind {
289			return []string{"wt rebase --all"}
290		}
291		return nil
292	}
