294	// findPRJSON finds the PR for a branch and converts it to JSON format.
295	func findPRJSON(branch string, openPRs, mergedPRs, closedPRs []github.PR) *listJSONPR {
296		if pr := github.FindPRForBranch(openPRs, branch); pr != nil {
297			rs := pr.GetReviewSummary()
298			cs := pr.GetCISummary()
299			return &listJSONPR{
300				Number: pr.Number,
301				State:  "open",
302				Review: listJSONReview{Approved: rs.Approved, Changes: rs.Changes, Pending: rs.Pending},
303				CI:     listJSONCI{Pass: cs.Pass, Fail: cs.Fail, Pending: cs.Pending, Total: cs.Total},
304			}
305		}
306		if pr := github.FindPRForBranch(mergedPRs, branch); pr != nil {
307			return &listJSONPR{Number: pr.Number, State: "merged"}
308		}
309		if pr := github.FindPRForBranch(closedPRs, branch); pr != nil {
310			return &listJSONPR{Number: pr.Number, State: "closed"}
311		}
312		return nil
313	}
