315	func runListTerminal(ctx *cmdContext, cwd string, worktrees []git.Worktree) error {
316		infos, featureBranches := collectWorktreeInfos(ctx, cwd, worktrees)
317	
318		// Phase 1: Show worktree names immediately
319		ui.Header("WORKTREES")
320	
321		// Calculate column width from longest short name
322		nameWidth := 0
323		for _, info := range infos {
324			if len(info.ShortName) > nameWidth {
325				nameWidth = len(info.ShortName)
326			}
327		}
328		if nameWidth < 8 {
329			nameWidth = 8
330		}
331	
332		ui.DimF("  %-*s %s\n", nameWidth+2, "Name", "Branch")
333		ui.DimF("  %s\n", strings.Repeat("─", nameWidth+2+28))
334	
335		for _, info := range infos {
336			if info.IsCurrent {
337				fmt.Printf("%s ", ui.Yellow(ui.Current))
338			} else {
339				fmt.Print("  ")
340			}
341	
342			fmt.Printf("%-*s ", nameWidth, info.ShortName)
343	
344			if info.Branch != info.ShortName {
345				fmt.Print(ui.Dim(info.Branch))
346			}
347	
348			fmt.Println()
349		}
350	
351		// Phase 2: PR status for feature branches
352		if len(featureBranches) > 0 && github.IsAvailable() {
353			fmt.Println()
354			spin := ui.NewSpinner("Loading PR status")
355	
356			openPRs, mergedPRs, closedPRs, hasErrors := fetchPRData()
357	
358			spin.Stop()
359	
360			if hasErrors {
361				ui.Warn("Could not fetch some PR data — status may be incomplete")
362			}
363	
364			staleThreshold := ctx.Config.EffectiveStaleThreshold()
365	
366			ui.DimF("  %-28s %-4s %-6s %-8s %-6s %-8s %s\n", "Branch", "Age", "Dirty", "Sync", "PR", "Review", "CI")
367			ui.DimF("  %s\n", strings.Repeat("─", 76))
368	
369			hasStale := false
370	
371			for _, info := range infos {
372				if ctx.isBaseBranch(info.Branch) {
373					continue
374				}
375	
376				openPR := github.FindPRForBranch(openPRs, info.Branch)
377				mergedPR := github.FindPRForBranch(mergedPRs, info.Branch)
378				closedPR := github.FindPRForBranch(closedPRs, info.Branch)
379	
380				// Check staleness: old commit + no open PR
381				daysAgo := git.LastCommitDaysAgo(info.Path)
382				isStale := daysAgo >= staleThreshold && openPR == nil
383	
384				// Dim the entire row if stale
385				colorize := fmt.Sprintf
386				if isStale {
387					colorize = func(f string, a ...any) string {
388						return ui.Dim(fmt.Sprintf(f, a...))
389					}
390				}
391	
392				branchDisplay := ui.Truncate(info.Branch, 28)
393				fmt.Printf("  %s ", colorize("%-28s", branchDisplay))
394	
395				// Age
396				fmt.Printf("%s ", colorize("%-4s", info.Age))
397	
398				// Dirty
399				if info.DirtyCount > 0 {
400					if isStale {
401						fmt.Printf("%s ", colorize("%-6d", info.DirtyCount))
402					} else {
403						ui.YellowF("%-6d ", info.DirtyCount)
404					}
405				} else {
406					fmt.Printf("%s ", ui.Dim(fmt.Sprintf("%-6s", ui.Dash)))
407				}
408	
409				// Sync
410				syncStr := buildSyncStr(info.Behind, info.Ahead)
411				switch {
412				case isStale:
413					fmt.Printf("%s ", colorize("%-8s", syncStr))
414				case info.Behind > 0:
415					ui.YellowF("%-8s ", syncStr)
416				default:
417					ui.GreenF("%-8s ", syncStr)
418				}
419	
420				// PR status
421				switch {
422				case openPR != nil:
423					printOpenPRStatus(openPR, info.Path)
424				case mergedPR != nil:
425					ui.BlueF("%-6s ", fmt.Sprintf("#%d", mergedPR.Number))
426					fmt.Printf("%s   %s", ui.Green("merged"), ui.Yellow("stale"))
427					hasStale = true
428					fmt.Println()
429				case closedPR != nil:
430					ui.BlueF("%-6s ", fmt.Sprintf("#%d", closedPR.Number))
431					fmt.Printf("%s  %s", ui.Red("closed"), ui.Yellow("stale"))
432					hasStale = true
433					fmt.Println()
434				default:
435					if isStale {
436						fmt.Print(ui.Dim(ui.Dash))
437						fmt.Print(" \U0001f4a4") // 💤
438					} else {
439						fmt.Print(ui.Dim(ui.Dash))
440					}
441					fmt.Println()
442				}
443			}
444	
445			// Legend
446			fmt.Println()
447			ui.DimF("  %s pending  %s changes/fail  %s pass\n", ui.Pending, ui.Fail, ui.Pass)
448	
449			if hasStale {
450				fmt.Printf("  %s\n", ui.Yellow("Tip: run 'wt prune' to clean up stale worktrees"))
451			}
452		}
453	
454		fmt.Println()
455		return nil
456	}
457	
458	func buildSyncStr(behind, ahead int) string {
459		var parts []string
460		if behind > 0 {
461			parts = append(parts, fmt.Sprintf("%s%d", ui.ArrowDown, behind))
462		}
463		if ahead > 0 {
464			parts = append(parts, fmt.Sprintf("%s%d", ui.ArrowUp, ahead))
465		}
466		if len(parts) == 0 {
467			return ui.Pass
468		}
469		return strings.Join(parts, "")
470	}
471	
472	func printOpenPRStatus(pr *github.PR, wtPath string) {
473		// PR number
474		ui.BlueF("%-6s ", fmt.Sprintf("#%d", pr.Number))
475	
476		// Review glyphs
477		rs := pr.GetReviewSummary()
478		reviewWidth := 8
479		reviewCount := 0
480	
481		if rs.Approved > 0 {
482			fmt.Print(ui.Green(strings.Repeat(ui.Pass, rs.Approved)))
483			reviewCount += rs.Approved
484		}
485		if rs.Changes > 0 {
486			fmt.Print(ui.Red(strings.Repeat(ui.Fail, rs.Changes)))
487			reviewCount += rs.Changes
488		}
489		if rs.Pending > 0 {
490			fmt.Print(ui.Blue(strings.Repeat(ui.Pending, rs.Pending)))
491			reviewCount += rs.Pending
492		}
493		if reviewCount == 0 {
494			fmt.Print(ui.Dim(ui.NoReview))
495			reviewCount = 1
496		}
497	
498		// Pad to fixed width
499		if pad := reviewWidth - reviewCount; pad > 0 {
500			fmt.Printf("%*s", pad, "")
501		}
502		fmt.Print(" ")
503	
504		// CI glyphs
505		cs := pr.GetCISummary()
506		if cs.Pass > 0 {
507			fmt.Print(ui.Green(strings.Repeat(ui.Pass, cs.Pass)))
508		}
509		if cs.Fail > 0 {
510			fmt.Print(ui.Red(strings.Repeat(ui.Fail, cs.Fail)))
511		}
512		if cs.Pending > 0 {
513			fmt.Print(ui.Yellow(strings.Repeat(ui.Pending, cs.Pending)))
514		}
515		if cs.Total == 0 {
516			fmt.Print(ui.Dim(ui.NoReview))
517		}
518	
519		// Unpushed indicator
520		unpushed := git.UnpushedCountIn(wtPath)
521		if unpushed > 0 {
522			fmt.Printf(" %s", ui.Magenta(fmt.Sprintf("%s%d", ui.PushUp, unpushed)))
523		}
524	
525		fmt.Println()
526	}
