49	// isAllDigits reports whether s is non-empty and contains only ASCII digits.
50	func isAllDigits(s string) bool {
51		if s == "" {
52			return false
53		}
54		for _, c := range s {
55			if c < '0' || c > '9' {
56				return false
57			}
58		}
59		return true
60	}
