62	// watchResult describes why the watch loop ended.
63	type watchResult struct {
64		success bool
65		message string
66	}
67	
68	func runWatch(cmd *cobra.Command, args []string) error {
69		if !github.IsAvailable() {
70			return fmt.Errorf("gh CLI is required for this command (brew install gh)")
71		}
72	
73		ctx, err := newContext()
74		if err != nil {
75			return err
76		}
77	
78		// Resolve what to watch: PR number, worktree name, or current branch
79		var ref string
80		if len(args) > 0 {
81			if isAllDigits(args[0]) {
82				// PR number — use directly
83				ref = args[0]
84			} else {
85				// Fuzzy-match against worktrees
86				worktrees, err := git.ListWorktrees()
87				if err != nil {
88					return err
89				}
90				target, _, resolveErr := resolveWorktree(ctx, worktrees, args[0])
91				if resolveErr != nil {
92					return resolveErr
93				}
94				if target == "" {
95					return fmt.Errorf("worktree not found: %s\n   Run wt list to see available worktrees", args[0])
96				}
97				branch, err := git.CurrentBranchIn(target)
98				if err != nil {
99					return fmt.Errorf("could not determine branch for worktree: %s", args[0])
100				}
101				ref = branch
102			}
103		} else {
104			branch, err := git.CurrentBranch()
105			if err != nil {
106				return fmt.Errorf("not in a git repository or detached HEAD\n   Run this from inside a worktree")
107			}
108	
109			if ctx.isBaseBranch(branch) {
110				return fmt.Errorf("can't watch the base branch (%s) %s it has no associated PR\n   Switch to a feature worktree first", branch, ui.Dash)
111			}
112			ref = branch
113		}
114	
115		// Initial fetch to verify PR exists
116		ws, err := github.GetWatchStatus(ref)
117		if err != nil {
118			return fmt.Errorf("could not fetch PR status for %s: %w", ref, err)
119		}
120	
121		// Resolve merge method once up front (2 gh calls — no need to repeat per poll)
122		mergeMethod := ""
123		if watchMergeFlag {
124			m, err := github.GetDefaultMergeMethod()
125			if err != nil {
126				ui.Warn("Could not determine merge method, defaulting to merge: %v", err)
127				m = "merge"
128			}
129			mergeMethod = m
130		}
131	
132		// Print header (once)
133		printWatchHeader(ws)
134	
135		// Check if already resolved
136		if res := checkResolved(ws); res != nil {
137			renderWatchTable(ws)
138			printWatchVerdict(ws)
139			if err := mergeIfRequested(ws, mergeMethod); err != nil {
140				return err
141			}
142			printWatchCTA(ws)
143			if res.success {
144				return nil
145			}
146			return errSilent
147		}
148	
149		// Set up Ctrl+C handler
150		sigCh := make(chan os.Signal, 1)
151		signal.Notify(sigCh, os.Interrupt)
152		defer signal.Stop(sigCh)
153	
154		// Poll loop
155		ticker := time.NewTicker(15 * time.Second)
156		defer ticker.Stop()
157	
158		tableLines := renderWatchTable(ws)
159		spin := ui.NewSpinnerRich(buildSpinnerMessage(ws))
160	
161		for {
162			select {
163			case <-sigCh:
164				spin.Stop()
165				fmt.Println()
166				return nil
167	
168			case <-ticker.C:
169				ws, err = github.GetWatchStatus(ref)
170				if err != nil {
171					spin.Stop()
172					return fmt.Errorf("failed to fetch PR status: %w", err)
173				}
174	
175				// Clear and redraw
176				spin.Stop()
177				ui.ClearLines(tableLines)
178	
179				if res := checkResolved(ws); res != nil {
180					renderWatchTable(ws)
181					printWatchVerdict(ws)
182					if err := mergeIfRequested(ws, mergeMethod); err != nil {
183						return err
184					}
185					printWatchCTA(ws)
186					sendNotification(ws)
187					if res.success {
188						return nil
189					}
190					return errSilent
191				}
192	
193				tableLines = renderWatchTable(ws)
194				spin = ui.NewSpinnerRich(buildSpinnerMessage(ws))
195			}
196		}
197	}
