199	// checkResolved returns a result if the PR has reached a terminal state, or nil to keep polling.
200	func checkResolved(ws *github.WatchStatus) *watchResult {
201		// Already merged
202		if ws.State == "MERGED" {
203			return &watchResult{success: true, message: "Already merged"}
204		}
205	
206		// Closed without merge
207		if ws.State == "CLOSED" {
208			return &watchResult{success: false, message: "PR was closed"}
209		}
210	
211		// Draft PR — always terminal, but verdict prints all concurrent issues
212		if ws.MergeStateStatus == "DRAFT" {
213			return &watchResult{success: false, message: "PR is a draft " + ui.Dash + " mark as ready first"}
214		}
215	
216		// Ready to merge
217		if ws.MergeStateStatus == "CLEAN" {
218			return &watchResult{success: true, message: "Ready to merge"}
219		}
220	
221		// Merge conflict
222		if ws.Mergeable == "CONFLICTING" {
223			return &watchResult{success: false, message: "Merge conflict " + ui.Dash + " run wt rebase"}
224		}
225	
226		// Changes requested
227		if ws.ReviewDecision == "CHANGES_REQUESTED" {
228			return &watchResult{success: false, message: "Changes requested"}
229		}
230	
231		// All CI resolved with failures
232		cs := ws.GetCISummary()
233		if cs.Total > 0 && cs.Pending == 0 && cs.Fail > 0 {
234			return &watchResult{
235				success: false,
236				message: fmt.Sprintf("%d check(s) failed", cs.Fail),
237			}
238		}
239	
240		// All CI resolved, all passed, but still BLOCKED (branch protection rules)
241		if cs.Total > 0 && cs.Pending == 0 && cs.Fail == 0 && ws.MergeStateStatus == "BLOCKED" {
242			return &watchResult{success: false, message: "Blocked by branch protection"}
243		}
244	
245		return nil
246	}
