338	// formatReviewItem returns the glyph and text for a review item separately,
339	// so the caller can pad the text correctly (ANSI codes break %-*s alignment).
340	func formatReviewItem(item github.ReviewItem) (glyph, text string) {
341		login := ui.Truncate(item.Login, 16)
342		switch item.State {
343		case "approved":
344			return ui.Green(ui.Pass), login + "  " + ui.Dim("approved")
345		case "changes_requested":
346			return ui.Red(ui.Fail), login + "  " + ui.Dim("changes")
347		default:
348			return ui.Blue(ui.Pending), login + "  " + ui.Dim("pending")
349		}
350	}
