352	// buildSpinnerMessage creates a concise status message for the spinner line.
353	func buildSpinnerMessage(ws *github.WatchStatus) string {
354		cs := ws.GetCISummary()
355	
356		ciWaiting := cs.Pending > 0 || cs.Total == 0
357		reviewWaiting := ws.ReviewDecision == "REVIEW_REQUIRED"
358	
359		switch {
360		case ciWaiting && reviewWaiting:
361			return ui.Dim("Waiting for checks and review...")
362		case ciWaiting:
363			if cs.Total > 0 {
364				return ui.Dim(fmt.Sprintf("Waiting for %d check(s)...", cs.Pending))
365			}
366			return ui.Dim("Waiting for status...")
367		case reviewWaiting:
368			return ui.Dim("Waiting for review...")
369		default:
370			return ui.Dim("Waiting for status...")
371		}
372	}
