374	// printWatchVerdict outputs the final success/error line after resolution.
375	func printWatchVerdict(ws *github.WatchStatus) {
376		cs := ws.GetCISummary()
377	
378		// Terminal bell
379		fmt.Print("\a")
380	
381		// Draft PRs: show all concurrent issues so the user sees everything to fix
382		if ws.MergeStateStatus == "DRAFT" {
383			if ws.Mergeable == "CONFLICTING" {
384				ui.Error("Merge conflict %s run wt rebase", ui.Dash)
385			}
386			if ws.ReviewDecision == "CHANGES_REQUESTED" {
387				ui.Error("Changes requested")
388			}
389			if cs.Fail > 0 {
390				ui.Error("%d check(s) failed", cs.Fail)
391			}
392			ui.Error("PR is a draft %s mark as ready first", ui.Dash)
393			return
394		}
395	
396		switch {
397		case ws.State == "MERGED":
398			ui.Success("Already merged")
399		case ws.State == "CLOSED":
400			ui.Error("PR was closed")
401		case ws.MergeStateStatus == "CLEAN":
402			ui.Success("Ready to merge")
403		case ws.Mergeable == "CONFLICTING":
404			ui.Error("Merge conflict %s run wt rebase", ui.Dash)
405		case ws.ReviewDecision == "CHANGES_REQUESTED":
406			ui.Error("Changes requested")
407		case cs.Fail > 0:
408			ui.Error("%d check(s) failed", cs.Fail)
409		case ws.MergeStateStatus == "BLOCKED":
410			ui.Error("Blocked by branch protection")
411		}
412	}
413	
414	// mergeIfRequested merges the PR when --merge is set and the PR is CLEAN.
415	// method is the merge strategy resolved once before the poll loop.
416	func mergeIfRequested(ws *github.WatchStatus, method string) error {
417		if !watchMergeFlag || ws.MergeStateStatus != "CLEAN" {
418			return nil
419		}
420		fmt.Printf("\nMerging PR #%d (%s)...\n", ws.Number, method)
421		if err := github.MergePR(ws.Number, method); err != nil {
422			return fmt.Errorf("merge failed: %w", err)
423		}
424		fmt.Println()
425		ui.Success("Merged PR #%d", ws.Number)
426		ui.PrintCTA("wt close")
427		return nil
428	}
429	
430	// printWatchCTA emits agent call-to-action hints based on the terminal PR state.
431	func printWatchCTA(ws *github.WatchStatus) {
432		switch {
433		case ws.State == "MERGED", ws.State == "CLOSED":
434			ui.PrintCTA("wt close")
435		case ws.MergeStateStatus == "CLEAN" && !watchMergeFlag:
436			ui.PrintCTA("wt open")
437		case ws.Mergeable == "CONFLICTING":
438			ui.PrintCTA("wt rebase")
439		}
440	}
441	
442	// sendNotification sends a desktop notification on macOS.
443	func sendNotification(ws *github.WatchStatus) {
444		if runtime.GOOS != "darwin" {
445			return
446		}
447	
448		title := fmt.Sprintf("PR #%d", ws.Number)
