1	package cmd
2	
3	import (
4		"fmt"
5		"os"
6		"os/exec"
7		"path/filepath"
8		"strings"
9	
10		"github.com/mvwi/wt/internal/git"
11		"github.com/mvwi/wt/internal/ui"
12		"github.com/spf13/cobra"
13	)
14	
15	const prevWorktreeStateFile = "wt-prev-worktree"
16	
17	var switchCmd = &cobra.Command{
18		Use:     "switch [name]",
19		Aliases: []string{"sw", "cd", "checkout", "co"},
20		GroupID: groupWorkflow,
21		Short:   "Switch to a worktree",
22		Long: `Switch to a different worktree.
23	
24	Without arguments, opens an interactive picker (requires fzf).
25	With a name, resolves the worktree using fuzzy matching.
26	Use "-" to switch back to the previous worktree.
27	
28	Resolution order:
29	  1. Exact match: wt-<repo>-<name>
30	  2. Main repo: 'main', base branch name, or repo name
31	  3. Branch name: exact match against the git branch
32	  4. Suffix match: any worktree ending with -<name>
33	  5. Fuzzy match: worktree or branch containing the search term`,
34		Example: `  wt switch               Interactive picker (requires fzf)
35	  wt switch sidebar        Switch to "sidebar" worktree (fuzzy match)
36	  wt switch -              Switch back to previous worktree
37	  wt switch main           Switch to main repository`,
38		Args:              cobra.MaximumNArgs(1),
39		ValidArgsFunction: completeWorktreeNames,
40		RunE:              runSwitch,
41	}
42	
43	func init() {
44		rootCmd.AddCommand(switchCmd)
45	}
46	
47	func runSwitch(cmd *cobra.Command, args []string) error {
48		ctx, err := newContext()
49		if err != nil {
50			return err
51		}
52	
53		worktrees, err := git.ListWorktrees()
54		if err != nil {
55			return err
56		}
57	
58		cwd, err := os.Getwd()
59		if err != nil {
60			return fmt.Errorf("cannot determine current directory: %w", err)
61		}
62	
63		// Handle "wt switch -" — toggle to previous worktree
64		if len(args) == 1 && args[0] == "-" {
65			return switchPrevious(cwd)
66		}
67	
68		// No args: interactive fzf picker
69		if len(args) == 0 {
70			return switchInteractive(ctx, worktrees, cwd)
71		}
72	
73		return switchByName(ctx, worktrees, cwd, args[0])
74	}
75	
76	func switchPrevious(cwd string) error {
77		prev, err := git.ReadStateFile(prevWorktreeStateFile)
78		if err != nil {
79			return fmt.Errorf("no previous worktree to switch to\n   Use wt switch <name> to specify one")
80		}
81	
82		prev = strings.TrimSpace(prev)
83		if !isDir(prev) {
84			return fmt.Errorf("previous worktree no longer exists: %s\n   It may have been closed. Run wt list to see available worktrees", prev)
85		}
86	
87		savePreviousWorktree(cwd)
88		ui.PrintCdHint(prev)
89		return nil
90	}
91	
92	func savePreviousWorktree(cwd string) {
93		_ = git.SaveStateFile(prevWorktreeStateFile, cwd)
94	}
95	
96	func switchInteractive(ctx *cmdContext, worktrees []git.Worktree, cwd string) error {
97		if _, err := exec.LookPath("fzf"); err != nil {
98			fmt.Println("Usage: wt switch <name>")
99			fmt.Println()
100			ui.DimF("Tip: Install fzf for interactive picker (brew install fzf)\n")
101			return nil
102		}
103	
104		// Build fzf input
105		var lines []string
106		for _, wt := range worktrees {
107			short := ctx.shortName(wt.Path)
108			branch, _ := git.CurrentBranchIn(wt.Path)
109			marker := "  "
110			if wt.Path == cwd || isSubpath(cwd, wt.Path) {
111				marker = ui.Current + " "
112			}
113			lines = append(lines, fmt.Sprintf("%s%s|%s|%s", marker, short, branch, wt.Path))
114		}
115	
116		input := strings.Join(lines, "\n")
117		fzfCmd := exec.Command("fzf", "--ansi", "--no-sort", "--reverse",
118			"--prompt=Switch to: ",
119			"--header=↑↓ navigate  enter select  esc cancel",
120			"--delimiter=|",
121			"--with-nth=1,2",
122			"--preview-window=hidden")
123		fzfCmd.Stdin = strings.NewReader(input)
124		fzfCmd.Stderr = os.Stderr
125	
126		out, err := fzfCmd.Output()
127		if err != nil {
128			if exitErr, ok := err.(*exec.ExitError); ok {
129				// exit code 130 = interrupted (Ctrl-C/Esc), 1 = no match
130				if exitErr.ExitCode() == 130 || exitErr.ExitCode() == 1 {
131					fmt.Println("Cancelled")
132					return nil
133				}
134			}
135			return fmt.Errorf("fzf error: %w", err)
136		}
137	
138		selection := strings.TrimSpace(string(out))
139		parts := strings.Split(selection, "|")
140		if len(parts) < 3 {
141			return fmt.Errorf("unexpected fzf output")
142		}
143	
144		target := parts[2]
145		savePreviousWorktree(cwd)
146		ui.PrintCdHint(target)
147		showSwitchSummary(target, ctx)
148		return nil
149	}
150	
151	func switchByName(ctx *cmdContext, worktrees []git.Worktree, cwd, name string) error {
152		target, _, err := resolveWorktree(ctx, worktrees, name)
153		if err != nil {
154			return err
155		}
156		if target == "" {
157			return fmt.Errorf("worktree not found: %s\n   Run wt list to see available worktrees", name)
158		}
159	
160		savePreviousWorktree(cwd)
161		ui.PrintCdHint(target)
162		showSwitchSummary(target, ctx)
163		return nil
164	}
165	
166	// resolveWorktree finds a worktree path by name using the resolution chain.
167	// Returns (path, fuzzy, nil) on success — fuzzy=true when the match came from
168	// the substring-contains step (step 5), meaning the caller should confirm
169	// before destructive actions. Returns ("", false, nil) when no match is found,
170	// or ("", false, error) when the match is ambiguous (error message already
171	// printed; returns errSilent).
172	func resolveWorktree(ctx *cmdContext, worktrees []git.Worktree, name string) (string, bool, error) {
173		// 1. Exact match with configured prefix
174		exact := ctx.worktreePath(name)
175		if isDir(exact) {
176			return exact, false, nil
177		}
178	
179		// 2. Main repo match (base branch name, "main", "master", or repo name)
180		if name == ctx.RepoName || ctx.isBaseBranch(name) {
181			return ctx.MainWorktree, false, nil
182		}
183	
184		// 3. Branch name match (exact match against git branch)
185		for _, wt := range worktrees {
186			if wt.Branch == name {
187				return wt.Path, false, nil
188			}
189		}
190	
191		// 4. Suffix match
192		for _, wt := range worktrees {
193			base := filepath.Base(wt.Path)
194			if strings.HasSuffix(base, "-"+name) || strings.HasSuffix(base, "/"+name) {
195				return wt.Path, false, nil
196			}
197		}
198	
199		// 5. Fuzzy match (contains) — checks both short name and branch
200		var fuzzyMatches []git.Worktree
201		nameLower := strings.ToLower(name)
202		for _, wt := range worktrees {
203			short := ctx.shortName(wt.Path)
204			if strings.Contains(strings.ToLower(short), nameLower) ||
205				strings.Contains(strings.ToLower(wt.Branch), nameLower) {
206				fuzzyMatches = append(fuzzyMatches, wt)
207			}
208		}
209	
210		if len(fuzzyMatches) == 1 {
211			short := ctx.shortName(fuzzyMatches[0].Path)
212			ui.DimF("Fuzzy matched: %s → %s\n", name, short)
213			return fuzzyMatches[0].Path, true, nil
214		}
215		if len(fuzzyMatches) > 1 {
216			fmt.Printf("Multiple matches for '%s':\n\n", name)
217			for _, m := range fuzzyMatches {
218				fmt.Printf("  %s\n", ctx.shortName(m.Path))
219			}
220			fmt.Println()
221			fmt.Println("Be more specific, or use 'wt switch' for interactive picker")
