package cmd

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"

	"github.com/mvwi/wt/internal/git"
	"github.com/mvwi/wt/internal/ui"
	"github.com/spf13/cobra"
)

const prevWorktreeStateFile = "wt-prev-worktree"

var switchCmd = &cobra.Command{
	Use:     "switch [name]",
	Aliases: []string{"sw", "cd", "checkout", "co"},
	GroupID: groupWorkflow,
	Short:   "Switch to a worktree",
	Long: `Switch to a different worktree.

Without arguments, opens an interactive picker (requires fzf).
With a name, resolves the worktree using fuzzy matching.
Use "-" to switch back to the previous worktree.

Resolution order:
  1. Exact match: wt-<repo>-<name>
  2. Main repo: 'main', base branch name, or repo name
  3. Branch name: exact match against the git branch
  4. Suffix match: any worktree ending with -<name>
  5. Fuzzy match: worktree or branch containing the search term`,
	Example: `  wt switch               Interactive picker (requires fzf)
  wt switch sidebar        Switch to "sidebar" worktree (fuzzy match)
  wt switch -              Switch back to previous worktree
  wt switch main           Switch to main repository`,
	Args:              cobra.MaximumNArgs(1),
	ValidArgsFunction: completeWorktreeNames,
	RunE:              runSwitch,
}

func init() {
	rootCmd.AddCommand(switchCmd)
}

func runSwitch(cmd *cobra.Command, args []string) error {
	ctx, err := newContext()
	if err != nil {
		return err
	}

	worktrees, err := git.ListWorktrees()
	if err != nil {
		return err
	}

	cwd, err := os.Getwd()
	if err != nil {
		return fmt.Errorf("cannot determine current directory: %w", err)
	}

	// Handle "wt switch -" — toggle to previous worktree
	if len(args) == 1 && args[0] == "-" {
		return switchPrevious(cwd)
	}

	// No args: interactive fzf picker
	if len(args) == 0 {
		return switchInteractive(ctx, worktrees, cwd)
	}

	return switchByName(ctx, worktrees, cwd, args[0])
}

func switchPrevious(cwd string) error {
	prev, err := git.ReadStateFile(prevWorktreeStateFile)
	if err != nil {
		return fmt.Errorf("no previous worktree to switch to\n   Use wt switch <name> to specify one")
	}

	prev = strings.TrimSpace(prev)
	if !isDir(prev) {
		return fmt.Errorf("previous worktree no longer exists: %s\n   It may have been closed. Run wt list to see available worktrees", prev)
	}

	savePreviousWorktree(cwd)
	ui.PrintCdHint(prev)
	return nil
}

func savePreviousWorktree(cwd string) {
	_ = git.SaveStateFile(prevWorktreeStateFile, cwd)
}

func switchInteractive(ctx *cmdContext, worktrees []git.Worktree, cwd string) error {
	if _, err := exec.LookPath("fzf"); err != nil {
		fmt.Println("Usage: wt switch <name>")
		fmt.Println()
		ui.DimF("Tip: Install fzf for interactive picker (brew install fzf)\n")
		return nil
	}

	// Build fzf input
	var lines []string
	for _, wt := range worktrees {
		short := ctx.shortName(wt.Path)
		branch, _ := git.CurrentBranchIn(wt.Path)
		marker := "  "
		if wt.Path == cwd || isSubpath(cwd, wt.Path) {
			marker = ui.Current + " "
		}
		lines = append(lines, fmt.Sprintf("%s%s|%s|%s", marker, short, branch, wt.Path))
	}

	input := strings.Join(lines, "\n")
	fzfCmd := exec.Command("fzf", "--ansi", "--no-sort", "--reverse",
		"--prompt=Switch to: ",
		"--header=↑↓ navigate  enter select  esc cancel",
		"--delimiter=|",
		"--with-nth=1,2",
		"--preview-window=hidden")
	fzfCmd.Stdin = strings.NewReader(input)
	fzfCmd.Stderr = os.Stderr

	out, err := fzfCmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			// exit code 130 = interrupted (Ctrl-C/Esc), 1 = no match
			if exitErr.ExitCode() == 130 || exitErr.ExitCode() == 1 {
				fmt.Println("Cancelled")
				return nil
			}
		}
		return fmt.Errorf("fzf error: %w", err)
	}

	selection := strings.TrimSpace(string(out))
	parts := strings.Split(selection, "|")
	if len(parts) < 3 {
		return fmt.Errorf("unexpected fzf output")
	}

	target := parts[2]
	savePreviousWorktree(cwd)
	ui.PrintCdHint(target)
	showSwitchSummary(target, ctx)
	return nil
}

func switchByName(ctx *cmdContext, worktrees []git.Worktree, cwd, name string) error {
	target, _, err := resolveWorktree(ctx, worktrees, name)
	if err != nil {
		return err
	}
	if target == "" {
		return fmt.Errorf("worktree not found: %s\n   Run wt list to see available worktrees", name)
	}

	savePreviousWorktree(cwd)
	ui.PrintCdHint(target)
	showSwitchSummary(target, ctx)
	return nil
}

// resolveWorktree finds a worktree path by name using the resolution chain.
// Returns (path, fuzzy, nil) on success — fuzzy=true when the match came from
// the substring-contains step (step 5), meaning the caller should confirm
// before destructive actions. Returns ("", false, nil) when no match is found,
// or ("", false, error) when the match is ambiguous (error message already
// printed; returns errSilent).
func resolveWorktree(ctx *cmdContext, worktrees []git.Worktree, name string) (string, bool, error) {
	// 1. Exact match with configured prefix
	exact := ctx.worktreePath(name)
	if isDir(exact) {
		return exact, false, nil
	}

	// 2. Main repo match (base branch name, "main", "master", or repo name)
	if name == ctx.RepoName || ctx.isBaseBranch(name) {
		return ctx.MainWorktree, false, nil
	}

	// 3. Branch name match (exact match against git branch)
	for _, wt := range worktrees {
		if wt.Branch == name {
			return wt.Path, false, nil
		}
	}

	// 4. Suffix match
	for _, wt := range worktrees {
		base := filepath.Base(wt.Path)
		if strings.HasSuffix(base, "-"+name) || strings.HasSuffix(base, "/"+name) {
			return wt.Path, false, nil
		}
	}

	// 5. Fuzzy match (contains) — checks both short name and branch
	var fuzzyMatches []git.Worktree
	nameLower := strings.ToLower(name)
	for _, wt := range worktrees {
		short := ctx.shortName(wt.Path)
		if strings.Contains(strings.ToLower(short), nameLower) ||
			strings.Contains(strings.ToLower(wt.Branch), nameLower) {
			fuzzyMatches = append(fuzzyMatches, wt)
		}
	}

	if len(fuzzyMatches) == 1 {
		short := ctx.shortName(fuzzyMatches[0].Path)
		ui.DimF("Fuzzy matched: %s → %s\n", name, short)
		return fuzzyMatches[0].Path, true, nil
	}
	if len(fuzzyMatches) > 1 {
		fmt.Printf("Multiple matches for '%s':\n\n", name)
		for _, m := range fuzzyMatches {
			fmt.Printf("  %s\n", ctx.shortName(m.Path))
		}
		fmt.Println()
		fmt.Println("Be more specific, or use 'wt switch' for interactive picker")
		return "", false, errSilent
	}

	return "", false, nil
}

func showSwitchSummary(path string, ctx *cmdContext) {
	short := ctx.shortName(path)
	branch, _ := git.CurrentBranchIn(path)
	isBase := ctx.isBaseBranch(branch)

	fmt.Printf("%s %s", ui.Yellow(ui.Current), short)

	if branch != short && !isBase {
		fmt.Printf("  %s", ui.Dim(branch))
	}

	isBehind := false
	if !isBase {
		ab, err := git.GetAheadBehindIn(path, ctx.baseRef())
		if err == nil {
			if ab.Behind > 0 {
				fmt.Printf("  %s", ui.Yellow(fmt.Sprintf("⚠ %d behind", ab.Behind)))
				isBehind = true
			} else if ab.Ahead > 0 {
				fmt.Printf("  %s", ui.Green(ui.Pass))
			}
		}
	}

	fmt.Println()

	if !isBase {
		if isBehind {
			ui.PrintCTA("wt rebase", "wt init")
		} else {
			ui.PrintCTA("wt init")
		}
	}
}

package cmd

import (
	"fmt"
	"os"
	"path/filepath"
	"sync"

	"github.com/mvwi/wt/internal/git"
	"github.com/mvwi/wt/internal/github"
	"github.com/mvwi/wt/internal/ui"
	"github.com/spf13/cobra"
)

var pruneCmd = &cobra.Command{
	Use:     "prune",
	GroupID: groupManage,
	Short:   "Clean up stale worktrees (merged/closed PRs)",
	Long: `Interactively remove worktrees whose PRs have been merged or closed.

Skips:
  - Main worktree
  - Current worktree
  - Worktrees with uncommitted changes
  - Base/main branches`,
	Example: `  wt prune                 Interactively remove stale worktrees
  wt prune --dry-run       Show what would be removed
  wt prune --yes           Remove all stale worktrees without prompts`,
	RunE: runPrune,
}

var pruneDryRun bool

func init() {
	pruneCmd.Flags().BoolVar(&pruneDryRun, "dry-run", false, "show what would be removed without removing anything")
	rootCmd.AddCommand(pruneCmd)
}

type staleWorktree struct {
	Path   string
	Branch string
	Reason string
}

func runPrune(cmd *cobra.Command, args []string) error {
	if !github.IsAvailable() {
		return fmt.Errorf("gh CLI is required for prune (brew install gh)")
	}

	ctx, err := newContext()
	if err != nil {
		return err
	}

	cwd, err := os.Getwd()
	if err != nil {
		return fmt.Errorf("cannot determine current directory: %w", err)
	}

	spin := ui.NewSpinner("Scanning for stale worktrees")

	var mergedPRs, closedPRs []github.PR
	var mergedErr, closedErr error
	var wg sync.WaitGroup
	wg.Add(2)
	go func() { defer wg.Done(); mergedPRs, mergedErr = github.ListPRs("merged") }()
	go func() { defer wg.Done(); closedPRs, closedErr = github.ListPRs("closed") }()
	wg.Wait()

	if mergedErr != nil && closedErr != nil {
		spin.Stop()
		return fmt.Errorf("could not fetch PR data: %v", mergedErr)
	}

	worktrees, err := git.ListWorktrees()
	if err != nil {
		spin.Stop()
		return err
	}

	var stale []staleWorktree
	var skippedDirty []staleWorktree

	for _, wt := range worktrees {
		// Skip main
		if wt.Path == ctx.MainWorktree {
			continue
		}
		// Skip current
		if wt.Path == cwd || isSubpath(cwd, wt.Path) {
			continue
		}

		branch := wt.Branch
		if branch == "" {
			branch, _ = git.CurrentBranchIn(wt.Path)
		}
		if ctx.isBaseBranch(branch) {
			continue
		}

		// Check PR status
		mergedPR := github.FindPRForBranch(mergedPRs, branch)
		closedPR := github.FindPRForBranch(closedPRs, branch)

		var reason string
		switch {
		case mergedPR != nil:
			reason = fmt.Sprintf("PR #%d merged", mergedPR.Number)
		case closedPR != nil:
			reason = fmt.Sprintf("PR #%d closed", closedPR.Number)
		default:
			continue
		}

		// Stale but has uncommitted changes — track separately
		if git.HasChangesIn(wt.Path) {
			skippedDirty = append(skippedDirty, staleWorktree{wt.Path, branch, reason})
			continue
		}

		stale = append(stale, staleWorktree{wt.Path, branch, reason})
	}

	git.PruneWorktrees()

	spin.Stop()

	if mergedErr != nil || closedErr != nil {
		ui.Warn("Could not fetch some PR data — results may be incomplete")
	}

	if len(stale) == 0 {
		ui.Success("No stale worktrees found")
		printSkippedDirty(skippedDirty)
		return nil
	}

	fmt.Printf("Found %d stale worktree(s):\n\n", len(stale))

	// Dry-run: list what would be removed and exit
	if pruneDryRun {
		for _, s := range stale {
			short := filepath.Base(s.Path)
			fmt.Printf("  %s  %s\n", ui.Yellow(short), s.Reason)
			fmt.Printf("     %s\n", ui.Dim(s.Branch))
		}
		printSkippedDirty(skippedDirty)
		fmt.Println()
		fmt.Println("No changes made (--dry-run)")
		return nil
	}

	// Phase 1: collect decisions
	var toRemove []int

	for i, s := range stale {
		short := filepath.Base(s.Path)
		fmt.Printf("%s\n", ui.Yellow(short))
		fmt.Printf("  └─ %s\n", s.Branch)
		fmt.Printf("  └─ %s\n", s.Reason)
		if ui.Confirm("  Remove?", false) {
			toRemove = append(toRemove, i)
			fmt.Println("  → queued")
		} else {
			fmt.Println("  → skipped")
		}
		fmt.Println()
	}

	// Phase 2: execute removals
	if len(toRemove) == 0 {
		fmt.Println("No worktrees to remove")
		return nil
	}

	fmt.Printf("Removing %d worktree(s)...\n", len(toRemove))

	removedCount := 0
	for _, i := range toRemove {
		s := stale[i]
		short := filepath.Base(s.Path)

		if err := git.RemoveWorktree(s.Path); err != nil {
			fmt.Printf("  %s %s (failed)\n", ui.Red(ui.Fail), short)
			continue
		}

		if git.BranchExists(s.Branch) {
			_ = git.DeleteBranch(s.Branch)
		}
		fmt.Printf("  %s %s\n", ui.Green(ui.Pass), short)
		removedCount++
	}

	fmt.Println()
	ui.Success("Removed %d worktree(s)", removedCount)
	printSkippedDirty(skippedDirty)
	ui.PrintCTA("wt list")
	return nil
}

func printSkippedDirty(skipped []staleWorktree) {
	if len(skipped) == 0 {
		return
	}
	fmt.Println()
	for _, s := range skipped {
		short := filepath.Base(s.Path)
		fmt.Printf("  %s %s — %s, skipped (has uncommitted changes)\n", ui.Yellow("!"), short, s.Reason)
	}
}

package cmd

import (
	"errors"
	"fmt"
	"os"
	"strings"

	"github.com/mvwi/wt/internal/git"
	"github.com/mvwi/wt/internal/github"
	"github.com/mvwi/wt/internal/ui"
	"github.com/mvwi/wt/internal/update"
	"github.com/spf13/cobra"
)

// errSilent is returned when the error has already been printed and
// Execute should exit non-zero without printing anything extra.
var errSilent = errors.New("")

// Version is set at build time via -ldflags.
var Version = "dev"

var rootCmd = &cobra.Command{
	Use:   "wt",
	Short: "Git worktree manager",
	Long: `wt - Git Worktree Manager

A streamlined workflow for managing git worktrees. Create feature branches,
sync with your base branch, track PR status, and clean up when done.

Typical workflow:
  wt new feature        Create worktree + branch
  wt init               Initialize worktree (see .wt.toml)
  ...work on feature...
  wt submit             Rebase on base branch + push
  ...merge PR...
  wt prune              Clean up merged worktrees

Configuration:
  Global:    ~/.config/wt/config.toml
  Per-repo:  .wt.toml in repo root`,
	SilenceUsage:              true,
	SilenceErrors:             true,
	SuggestionsMinimumDistance: 2,
	Version:                   Version,
	RunE:                      runStatus,
}

// Command group IDs
const (
	groupWorkflow = "workflow"
	groupSync     = "sync"
	groupManage   = "manage"
)

// Execute runs the root command.
func Execute() {
	update.CheckInBackground()

	if err := rootCmd.Execute(); err != nil {
		if !errors.Is(err, errSilent) {
			// Cobra includes "Did you mean this?" in the error message
			// when SuggestionsMinimumDistance is set. Since we silence
			// errors to control output, we print the error ourselves.
			fmt.Fprintf(os.Stderr, "%s %s\n", ui.Red(ui.Fail), err)
		}
		os.Exit(1)
	}

	// Suppress update banner for shell-infrastructure commands that run
	// during shell init (their stderr is visible even though stdout is piped).
	if !isShellInitCommand() {
		if info := update.GetUpdateInfo(Version); info != nil {
			fmt.Fprintf(os.Stderr, "\n%s %s → %s\n",
				ui.Cyan(ui.PushUp+" Update available:"),
				ui.Dim(info.Current),
				ui.Cyan(info.Latest),
			)
			fmt.Fprintf(os.Stderr, "  %s\n", ui.Dim("brew upgrade wt"))
		}
	}
}

func init() {
	rootCmd.SetVersionTemplate("wt version {{.Version}}\n")
	rootCmd.CompletionOptions.HiddenDefaultCmd = true
	rootCmd.PersistentFlags().BoolVarP(&ui.YesFlag, "yes", "y", false, "skip confirmation prompts (answer yes to all)")

	rootCmd.AddGroup(
		&cobra.Group{ID: groupWorkflow, Title: "Workflow:"},
		&cobra.Group{ID: groupSync, Title: "Sync:"},
		&cobra.Group{ID: groupManage, Title: "Manage:"},
	)
}

// isShellInitCommand returns true for commands that run during shell startup
// (init-shell, completion) where stderr output would be disruptive.
func isShellInitCommand() bool {
	if len(os.Args) < 2 {
		return false
	}
	switch os.Args[1] {
	case "init-shell", "completion":
		return true
	}
	return false
}

// runStatus is called when `wt` is run with no subcommand.
// Shows a quick status of the current worktree, or help if not in a repo.
func runStatus(cmd *cobra.Command, args []string) error {
	if !git.IsInsideWorkTree() {
		return cmd.Help()
	}

	ctx, err := newContext()
	if err != nil {
		return cmd.Help()
	}

	cwd, err := os.Getwd()
	if err != nil {
		return fmt.Errorf("cannot determine current directory: %w", err)
	}
	branch, err := git.CurrentBranch()
	if err != nil {
		return cmd.Help()
	}

	// Worktree name
	short := ctx.shortName(cwd)
	isMain := cwd == ctx.MainWorktree || isSubpath(cwd, ctx.MainWorktree)

	fmt.Printf("%s %s", ui.Yellow(ui.Current), short)
	if branch != short {
		fmt.Printf("  %s", ui.Dim(branch))
	}
	fmt.Println()

	// Base/main branch: just show it
	if isMain || ctx.isBaseBranch(branch) {
		return nil
	}

	// Sync status
	ab, err := git.GetAheadBehind(ctx.baseRef())
	if err == nil {
		var parts []string
		if ab.Behind > 0 {
			parts = append(parts, ui.Yellow(fmt.Sprintf("%s%d behind %s", ui.ArrowDown, ab.Behind, ctx.Config.BaseBranch)))
		}
		if ab.Ahead > 0 {
			parts = append(parts, ui.Green(fmt.Sprintf("%s%d ahead", ui.ArrowUp, ab.Ahead)))
		}
		if len(parts) > 0 {
			fmt.Printf("  %s\n", strings.Join(parts, "  "))
		} else {
			fmt.Printf("  %s\n", ui.Green("up to date with "+ctx.Config.BaseBranch))
		}
	}

	// Uncommitted changes
	if git.HasChanges() {
		statusShort, _ := git.StatusShort()
		lines := strings.Split(strings.TrimSpace(statusShort), "\n")
		fmt.Printf("  %s\n", ui.Yellow(fmt.Sprintf("%d uncommitted change(s)", len(lines))))
	}

	// Unpushed commits
	unpushed := git.UnpushedCountIn(cwd)
	if unpushed > 0 {
		fmt.Printf("  %s\n", ui.Cyan(fmt.Sprintf("%s%d unpushed commit(s)", ui.PushUp, unpushed)))
	}

	// PR status
	if github.IsAvailable() {
		pr, _ := github.GetPRForBranch(branch)
		if pr != nil && pr.State == "OPEN" {
			rs := pr.GetReviewSummary()
			cs := pr.GetCISummary()

			prStr := fmt.Sprintf("PR #%d", pr.Number)
			var details []string
			if rs.Approved > 0 {
				details = append(details, fmt.Sprintf("%d approved", rs.Approved))
			}
			if rs.Changes > 0 {
				details = append(details, fmt.Sprintf("%d changes requested", rs.Changes))
			}
			if rs.Pending > 0 {
				details = append(details, fmt.Sprintf("%d pending", rs.Pending))
			}
			switch {
			case cs.Fail > 0:
				details = append(details, ui.Red("CI failing"))
			case cs.Pending > 0:
				details = append(details, ui.Yellow("CI pending"))
			case cs.Pass > 0:
				details = append(details, ui.Green("CI passing"))
			}

			if len(details) > 0 {
				fmt.Printf("  %s  %s\n", ui.Blue(prStr), strings.Join(details, ", "))
			} else {
				fmt.Printf("  %s\n", ui.Blue(prStr))
			}
		}
	}

	return nil
}

package cmd

import (
	"fmt"
	"os"
	"slices"
	"strings"

	"github.com/mvwi/wt/internal/git"
	"github.com/mvwi/wt/internal/ui"
	"github.com/spf13/cobra"
)

var rebaseCmd = &cobra.Command{
	Use:     "rebase",
	GroupID: groupSync,
	Short:   "Rebase current branch onto base branch (local only)",
	Long: `Rebase the current branch onto the configured base branch.

For feature branches: stash → fetch → rebase → restore stash.
For base/main branches: fast-forward merge only.

Use --all to rebase all worktrees at once.`,
	Example: `  wt rebase               Rebase current branch onto base branch
  wt rebase --all          Rebase all worktrees at once
  wt rebase --continue     Resume after resolving conflicts
  wt rebase --abort        Abort rebase and restore state`,
	RunE: runRebase,
}

var (
	rebaseContinueFlag bool
	rebaseAbortFlag    bool
	rebaseAllFlag      bool
)

func init() {
	rebaseCmd.Flags().BoolVar(&rebaseContinueFlag, "continue", false, "resume after resolving conflicts")
	rebaseCmd.Flags().BoolVar(&rebaseAbortFlag, "abort", false, "abort rebase and restore state")
	rebaseCmd.Flags().BoolVarP(&rebaseAllFlag, "all", "a", false, "rebase all worktrees")
	rootCmd.AddCommand(rebaseCmd)
}

const stateFileName = "wt-rebase-state"

type rebaseOpts struct {
	continueRebase bool
	abort          bool
	all            bool
}

func runRebase(cmd *cobra.Command, args []string) error {
	return runRebaseWith(rebaseOpts{
		continueRebase: rebaseContinueFlag,
		abort:          rebaseAbortFlag,
		all:            rebaseAllFlag,
	})
}

func runRebaseWith(opts rebaseOpts) error {
	ctx, err := newContext()
	if err != nil {
		return err
	}

	if opts.all && (opts.continueRebase || opts.abort) {
		return fmt.Errorf("--all cannot be combined with --continue or --abort")
	}

	if opts.all {
		return rebaseAll(ctx)
	}

	branch, err := git.CurrentBranch()
	if err != nil {
		return fmt.Errorf("not in a git repository or detached HEAD\n   Run this from inside a worktree")
	}

	if opts.continueRebase {
		return rebaseContinue(ctx)
	}
	if opts.abort {
		return rebaseAbort()
	}

	// Base branch: fast-forward
	if ctx.isBaseBranch(branch) {
		return rebaseBaseBranch(ctx, branch)
	}

	return rebaseFeatureBranch(ctx, branch)
}

func rebaseFeatureBranch(ctx *cmdContext, branch string) error {
	inProgress, _ := git.IsRebaseInProgress()
	if inProgress {
		return fmt.Errorf("rebase already in progress\n   Resolve conflicts and run: wt rebase --continue\n   Or abort with: wt rebase --abort")
	}

	preRef, _ := git.RevParseHead()

	fmt.Printf("Syncing branch: %s\n\n", branch)

	// Stash uncommitted changes
	didStash := false
	if git.HasChanges() {
		fmt.Println("Stashing uncommitted changes...")
		if err := git.StashPush("wt rebase: auto-stash"); err != nil {
			return fmt.Errorf("failed to stash changes: %w", err)
		}
		didStash = true
	}

	// Save state for --continue (format: "stash_state:pre_ref")
	stashState := "no"
	if didStash {
		stashState = "stashed"
	}
	_ = git.SaveStateFile(stateFileName, stashState+":"+preRef)

