func rebaseAbort() error {
	inProgress, _ := git.IsRebaseInProgress()
	hasState := git.StateFileExists(stateFileName)

	if !inProgress && !hasState {
		return fmt.Errorf("no rebase in progress\n   Start one with: wt rebase")
