package tui

import (
	"fmt"
	"strings"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// DashItem describes one worktree row in the dashboard.
type DashItem struct {
	Path        string
	ShortName   string
	Branch      string
	IsCurrent   bool
	IsBase      bool
	StaleDimmed bool // old commit + no open PR — dim the whole row

	Age        string
	Behind     int
	Ahead      int
	DirtyCount int
	Unpushed   int

	PR *DashPR // nil for base branches and worktrees with no PR
}

type DashPR struct {
	Number int
	State  string // "open", "merged", "closed"
	Review DashReview
	CI     DashCI
}

type DashReview struct {
	Approved, Changes, Pending int
}

type DashCI struct {
	Pass, Fail, Pending, Total int
}

// DashResult is returned to the caller after the dashboard exits.
// SwitchTo is the worktree path the user selected with Enter; empty means quit-without-action.
type DashResult struct {
	SwitchTo string
}

// RunDashboard launches the interactive worktree dashboard.
// `initial` is rendered immediately; `gather` is invoked on each refresh tick
// (and on manual refresh) to repopulate the list. The dashboard owns the
// terminal until the user presses enter (select) or q/esc/ctrl+c (quit).
func RunDashboard(initial []DashItem, gather func() ([]DashItem, error)) (DashResult, error) {
	m := dashModel{
		items:       initial,
		gather:      gather,
		lastRefresh: time.Now(),
	}

	final, err := tea.NewProgram(m, tea.WithAltScreen()).Run()
	if err != nil {
		return DashResult{}, err
	}

	fm := final.(dashModel)
	if fm.switchTo != "" {
		return DashResult{SwitchTo: fm.switchTo}, nil
	}
	return DashResult{}, nil
}

type dashModel struct {
	items       []DashItem
	gather      func() ([]DashItem, error)
	cursor      int
	width       int
	height      int
	refreshing  bool
	lastRefresh time.Time
	lastErr     error
	switchTo    string
}

type tickMsg time.Time

type refreshedMsg struct {
	items []DashItem
	err   error
}

const refreshInterval = 15 * time.Second

func tickCmd() tea.Cmd {
	return tea.Tick(refreshInterval, func(t time.Time) tea.Msg { return tickMsg(t) })
}

func refreshCmd(gather func() ([]DashItem, error)) tea.Cmd {
	return func() tea.Msg {
		items, err := gather()
		return refreshedMsg{items: items, err: err}
	}
}

func (m dashModel) Init() tea.Cmd {
	return tickCmd()
}

func (m dashModel) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case tea.KeyMsg:
		switch msg.String() {
		case "ctrl+c", "q", "esc":
			return m, tea.Quit
		case "up", "k":
			if m.cursor > 0 {
				m.cursor--
			}
		case "down", "j":
			if m.cursor < len(m.items)-1 {
				m.cursor++
			}
		case "g", "home":
			m.cursor = 0
		case "G", "end":
			m.cursor = max(0, len(m.items)-1)
		case "r":
			if !m.refreshing {
				m.refreshing = true
				return m, refreshCmd(m.gather)
			}
		case "enter":
			if m.cursor >= 0 && m.cursor < len(m.items) {
				m.switchTo = m.items[m.cursor].Path
				return m, tea.Quit
			}
		}

	case tickMsg:
		if m.refreshing {
			// Already refreshing — just reschedule the next tick.
			return m, tickCmd()
		}
		m.refreshing = true
		return m, tea.Batch(refreshCmd(m.gather), tickCmd())

	case refreshedMsg:
		m.refreshing = false
		if msg.err != nil {
			m.lastErr = msg.err
			return m, nil
		}
		m.items = msg.items
		m.lastErr = nil
		m.lastRefresh = time.Now()
		if m.cursor >= len(m.items) {
			m.cursor = max(0, len(m.items)-1)
		}
		return m, nil
	}

	return m, nil
}

// --- styles ---

var (
	dStyleHeader    = lipgloss.NewStyle().Foreground(lipgloss.Color("8"))
	dStyleCurrent   = lipgloss.NewStyle().Foreground(lipgloss.Color("11")).Bold(true)
	dStyleCursor    = lipgloss.NewStyle().Foreground(lipgloss.Color("11")).Bold(true)
	dStyleName      = lipgloss.NewStyle().Foreground(lipgloss.Color("11"))
	dStyleBranch    = lipgloss.NewStyle().Foreground(lipgloss.Color("8"))
	dStyleDim       = lipgloss.NewStyle().Foreground(lipgloss.Color("8"))
	dStyleGreen     = lipgloss.NewStyle().Foreground(lipgloss.Color("10"))
	dStyleYellow    = lipgloss.NewStyle().Foreground(lipgloss.Color("11"))
	dStyleRed       = lipgloss.NewStyle().Foreground(lipgloss.Color("9"))
	dStyleBlue      = lipgloss.NewStyle().Foreground(lipgloss.Color("12"))
	dStyleMagenta   = lipgloss.NewStyle().Foreground(lipgloss.Color("13"))
	dStyleCursorRow = lipgloss.NewStyle().Background(lipgloss.Color("237"))
)

// Column widths.
const (
	colBranch = 28
	colAge    = 4
	colDirty  = 4
	colSync   = 8
	colPR     = 6
	colReview = 8
	colCI     = 8
)

func (m dashModel) View() string {
	var b strings.Builder

	nameWidth := 8
	for _, it := range m.items {
		if w := lipgloss.Width(it.ShortName); w > nameWidth {
			nameWidth = w
		}
	}

	ruleWidth := nameWidth + 2 + colBranch + 1 + colAge + 1 + colDirty + 1 + colSync + 1 + colPR + 1 + colReview + 1 + colCI

	// Header
	b.WriteString("\n")
	b.WriteString("  " + dStyleHeader.Render("WORKTREES") + "\n")
	b.WriteString("  " + dStyleDim.Render(strings.Repeat("─", ruleWidth)) + "\n")

	// Column headers
	header := fmt.Sprintf("    %-*s  %-*s %-*s %-*s %-*s %-*s %-*s %-*s",
		nameWidth, "Name",
		colBranch, "Branch",
		colAge, "Age",
		colDirty, "Dirty",
		colSync, "Sync",
		colPR, "PR",
		colReview, "Review",
		colCI, "CI",
	)
	b.WriteString(dStyleDim.Render(header) + "\n")

	// Rows
	for i, it := range m.items {
		b.WriteString(renderRow(it, i == m.cursor, nameWidth))
		b.WriteString("\n")
	}

	// Footer
	b.WriteString("  " + dStyleDim.Render(strings.Repeat("─", ruleWidth)) + "\n")

	status := buildStatusLine(m)
	keys := dStyleDim.Render("↑↓ move · enter switch · r refresh · q quit")
	b.WriteString("  " + keys)
	if status != "" {
		pad := ruleWidth - lipgloss.Width(keys) - lipgloss.Width(status)
		if pad < 2 {
			pad = 2
		}
		b.WriteString(strings.Repeat(" ", pad) + status)
	}
	b.WriteString("\n")

	return b.String()
}

func buildStatusLine(m dashModel) string {
	if m.lastErr != nil {
		return dStyleRed.Render("refresh failed: " + truncate(m.lastErr.Error(), 30))
	}
	if m.refreshing {
		return dStyleDim.Render("refreshing…")
	}
	elapsed := time.Since(m.lastRefresh).Truncate(time.Second)
	return dStyleDim.Render(fmt.Sprintf("updated %s ago", elapsed))
}

func renderRow(it DashItem, isCursor bool, nameWidth int) string {
	currentGlyph := "  "
	if it.IsCurrent {
		currentGlyph = dStyleCurrent.Render("● ")
	}
	cursorGlyph := "  "
	if isCursor {
		cursorGlyph = dStyleCursor.Render("▸ ")
	}

	short := truncate(it.ShortName, nameWidth)
