2	
3	import (
4		"fmt"
5		"strconv"
6		"strings"
7		"time"
8	)
9	
10	// CurrentBranch returns the current branch name, or "" for detached HEAD.
11	func CurrentBranch() (string, error) {
12		return Run("rev-parse", "--abbrev-ref", "HEAD")
13	}
14	
15	// CurrentBranchIn returns the current branch for a specific worktree.
16	func CurrentBranchIn(dir string) (string, error) {
17		return RunIn(dir, "rev-parse", "--abbrev-ref", "HEAD")
18	}
19	
20	// BranchExists checks if a local branch exists.
21	func BranchExists(name string) bool {
22		return RunSilent("show-ref", "--verify", "--quiet", "refs/heads/"+name) == nil
23	}
24	
25	// RemoteBranchExists checks if a remote branch exists (e.g., "origin/feature").
26	func RemoteBranchExists(name string) bool {
27		return RunSilent("show-ref", "--verify", "--quiet", "refs/remotes/"+name) == nil
28	}
29	
30	// ResolveBranch tries to find a branch ref in order: local, remotes/<name>, remotes/origin/<name>.
31	// Returns the ref, whether it's remote, and any error.
32	func ResolveBranch(name, remote string) (ref string, isRemote bool, err error) {
33		// Local branch
34		if BranchExists(name) {
35			return name, false, nil
36		}
37		// Remote with explicit prefix (e.g., "origin/branch")
38		if RemoteBranchExists(name) {
39			return name, true, nil
40		}
41		// Remote without prefix
42		fullRemote := remote + "/" + name
43		if RemoteBranchExists(fullRemote) {
44			return fullRemote, true, nil
45		}
46		return "", false, fmt.Errorf("branch not found: %s (tried local and remote refs)", name)
47	}
48	
49	// RenameBranch renames a local branch.
50	func RenameBranch(oldName, newName string) error {
51		_, err := Run("branch", "-m", oldName, newName)
52		return err
53	}
54	
55	// DeleteBranch force-deletes a local branch.
56	func DeleteBranch(name string) error {
57		_, err := Run("branch", "-D", name)
58		return err
59	}
60	
61	// DeleteRemoteBranch deletes a branch on the remote.
