package tui

import (
	"fmt"
	"strings"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// DashItem describes one worktree row in the dashboard.
type DashItem struct {
	Path        string
	ShortName   string
	Branch      string
	IsCurrent   bool
	IsBase      bool
	StaleDimmed bool // old commit + no open PR — dim the whole row

	Age        string
	Behind     int
	Ahead      int
	DirtyCount int
	Unpushed   int

	PR *DashPR // nil for base branches and worktrees with no PR
}

type DashPR struct {
	Number int
	State  string // "open", "merged", "closed"
	Review DashReview
	CI     DashCI
}

type DashReview struct {
	Approved, Changes, Pending int
}

type DashCI struct {
	Pass, Fail, Pending, Total int
}

// DashResult is returned to the caller after the dashboard exits.
// SwitchTo is the worktree path the user selected with Enter; empty means quit-without-action.
type DashResult struct {
	SwitchTo string
}

// RunDashboard launches the interactive worktree dashboard.
// `initial` is rendered immediately; `gather` is invoked on each refresh tick
// (and on manual refresh) to repopulate the list. `prune` removes a worktree
// and its branch — invoked off the Update loop so multiple prunes can run
// concurrently while the user keeps navigating. Pass nil for prune to disable
// the in-dashboard prune action.
//
// The dashboard owns the terminal until the user presses enter (select) or
// q/esc/ctrl+c (quit).
func RunDashboard(
	initial []DashItem,
	gather func() ([]DashItem, error),
	prune func(path, branch string) error,
) (DashResult, error) {
	m := dashModel{
		items:       initial,
		gather:      gather,
		prune:       prune,
		prunes:      map[string]*dashPruneState{},
		lastRefresh: time.Now(),
	}

	final, err := tea.NewProgram(m, tea.WithAltScreen()).Run()
	if err != nil {
		return DashResult{}, err
	}

	fm := final.(dashModel)
	if fm.switchTo != "" {
		return DashResult{SwitchTo: fm.switchTo}, nil
	}
	return DashResult{}, nil
}

type dashModel struct {
	items       []DashItem
	gather      func() ([]DashItem, error)
	prune       func(path, branch string) error
	prunes      map[string]*dashPruneState // keyed by worktree path
	cursor      int
	width       int
	height      int
	refreshing  bool
	lastRefresh time.Time
	lastErr     error
	switchTo    string
}

// dashPruneState tracks an in-flight or recently-completed prune for one row.
// Persists in the model so the UI can render feedback ("pruning…", "✓ pruned",

