// renderDetail renders the bottom panel for the focused worktree. Returns ""
// when there's no focus. Width is the rule width — content is wrapped/truncated
// to fit, but no minimum height is enforced.
func (m dashModel) renderDetail(width int) string {
	if m.cursor < 0 || m.cursor >= len(m.items) {
		return ""
	}
	it := m.items[m.cursor]

	var b strings.Builder

	// Title line: name · branch [· PR #N title]
	title := dStyleName.Render(it.ShortName)
	if it.Branch != "" && it.Branch != it.ShortName {
		title += "  " + dStyleDim.Render("· "+it.Branch)
	}

	cache, hasCache := m.details[it.Path]

	if hasCache && cache.err == nil && it.PR != nil && cache.data.PRTitle != "" {
		title += "  " + dStyleDim.Render(fmt.Sprintf("· PR #%d %s", it.PR.Number, cache.data.PRTitle))
	}
	fmt.Fprintf(&b, "  %s\n", title)

	if !hasCache {
		fmt.Fprintf(&b, "  %s\n", dStyleDim.Render("loading detail…"))
		return b.String()
	}
	if cache.err != nil {
		fmt.Fprintf(&b, "  %s\n", dStyleRed.Render("detail unavailable: "+truncate(cache.err.Error(), width-22)))
		return b.String()
	}

	d := cache.data

	if d.PRAuthor != "" {
		fmt.Fprintf(&b, "  %s\n", dStyleDim.Render("opened by @"+d.PRAuthor))
	}
	if d.PRBody != "" {
		body := truncate(collapseWhitespace(d.PRBody), width-4)
		fmt.Fprintf(&b, "  %s\n", dStyleDim.Render(body))
	}

	// Diff stats
	if d.Stats.Commits > 0 || d.Stats.Files > 0 {
		fmt.Fprintf(&b, "\n  %s\n", buildStatsLine(d.Stats))
	}

	// Commits
	for _, c := range d.Commits {
		subj := truncate(c.Subject, width-26)
		fmt.Fprintf(&b, "    %s  %s  %s\n",
			dStyleDim.Render(c.Hash),
			subj,
			dStyleDim.Render(c.Age),
		)
	}

	// Files (compact one-liner)
	if len(d.Files) > 0 {
		fmt.Fprintf(&b, "  %s %s\n", dStyleDim.Render("Files:"), buildFilesLine(d.Files, width-10))
	}

	// Named CI checks
	if len(d.Checks) > 0 {
		fmt.Fprintf(&b, "  %s %s\n", dStyleDim.Render("CI:"), buildChecksLine(d.Checks, width-7))
	}

	return b.String()
}

func buildStatsLine(s DashDiffStats) string {
	plural := func(n int, w string) string {
		if n == 1 {
			return fmt.Sprintf("%d %s", n, w)
		}
		return fmt.Sprintf("%d %ss", n, w)
	}
	return fmt.Sprintf("%s ahead, %s %s across %s",
		plural(s.Commits, "commit"),
		dStyleGreen.Render(fmt.Sprintf("+%d", s.Additions)),
		dStyleRed.Render(fmt.Sprintf("−%d", s.Deletions)),
		plural(s.Files, "file"),
	)
}

func buildFilesLine(files []DashFileChange, maxWidth int) string {
	var parts []string
	used := 0
	for i, f := range files {
		var glyph string
		switch f.Status {
		case "A":
			glyph = dStyleGreen.Render("A")
		case "D":
			glyph = dStyleRed.Render("D")
		case "R":
			glyph = dStyleBlue.Render("R")
		default:
			glyph = dStyleYellow.Render(f.Status)
		}
		piece := glyph + " " + f.Path
		// approx visible width = len(status) + 1 + len(path)
		w := 1 + 1 + len(f.Path) + 2 // +2 for the separator
		if used+w > maxWidth && i > 0 {
			parts = append(parts, dStyleDim.Render(fmt.Sprintf("+%d more", len(files)-i)))
			break
		}
		parts = append(parts, piece)
		used += w
	}
	return strings.Join(parts, "  ")
}

func buildChecksLine(checks []DashCheck, maxWidth int) string {
	var parts []string
	used := 0
	for i, c := range checks {
		var glyph string
		switch c.State {
		case "pass":
			glyph = dStyleGreen.Render("✓")
		case "fail":
			glyph = dStyleRed.Render("✗")
		default:
			glyph = dStyleYellow.Render("◐")
		}
		piece := glyph + " " + c.Name
		w := 1 + 1 + len(c.Name) + 3
		if used+w > maxWidth && i > 0 {
			parts = append(parts, dStyleDim.Render(fmt.Sprintf("+%d more", len(checks)-i)))
			break
		}
		parts = append(parts, piece)
		used += w
	}
	return strings.Join(parts, " · ")
}

// collapseWhitespace replaces runs of whitespace (including newlines) with a
// single space — used to flatten multi-line PR bodies into a one-line summary.
func collapseWhitespace(s string) string {
	return strings.Join(strings.Fields(s), " ")
}

