// the first blank line). Whitespace-only input yields "".
func firstParagraph(body string) string {
	body = strings.TrimSpace(body)
	if body == "" {
		return ""
	}
	if idx := strings.Index(body, "\n\n"); idx >= 0 {
		body = body[:idx]
	}
	return strings.TrimSpace(body)
}

