	m := conventionalRe.FindStringSubmatch(subject)
	if m == nil {
		return strings.Repeat(" ", width), subject
	}
	typeWord := m[1]
	rest = subject[len(m[0]):]
	style := commitTypeStyle(typeWord)
	label := typeWord + ":"
	cell = style.Render(label) + strings.Repeat(" ", max(0, width-len(label)))
	return cell, rest
}

