// for the highlighted commit in the user's $PAGER.
func (m dashModel) handleCommitsKey(key string) (tea.Model, tea.Cmd) {
	commits := m.focusedCommits()
	switch key {
	case "up", "k":
		if m.commitCursor > 0 {
			m.commitCursor--
		}
	case "down", "j":
		if m.commitCursor < len(commits)-1 {
			m.commitCursor++
		}
	case "g", "home":
		m.commitCursor = 0
	case "G", "end":
		m.commitCursor = max(0, len(commits)-1)
	case "enter":
		if m.commitCursor >= 0 && m.commitCursor < len(commits) {
			path := m.items[m.cursor].Path
			hash := commits[m.commitCursor].Hash
			return m, tea.ExecProcess(gitShowCmd(path, hash), nil)
		}
	}
	return m, nil
}

// gitShowCmd builds the `git show` command used for commit drill-in.
// Drops --stat in favor of the full diff (you almost always want the diff
// when drilling in), and overrides Git's default LESS=FRX so the pager
// stays open even when the diff fits on one screen — otherwise short
// commits flash by instantly. User-set LESS is preserved.
func gitShowCmd(path, hash string) *exec.Cmd {
	cmd := exec.Command("git", "-C", path, "show", hash)
	if os.Getenv("LESS") == "" {
		cmd.Env = append(os.Environ(), "LESS=R")
	}
	return cmd
}

