package git

import (
	"fmt"
	"strconv"
	"strings"
)

// LogEntry is one commit summary used by the dashboard detail panel.
type LogEntry struct {
	Hash    string // short
	Subject string
	Age     string // already shortened, e.g. "2h"
}

// LogOnelineIn returns up to n commits reachable from HEAD but not from base,
// most recent first. Returns nil (not error) if the range is empty.
func LogOnelineIn(dir, base string, n int) ([]LogEntry, error) {
	if n <= 0 {
		return nil, nil
	}
	out, err := RunIn(dir, "log",
		fmt.Sprintf("-%d", n),
		"--format=%h\t%s\t%cr",
		base+"..HEAD",
	)
	if err != nil {
		return nil, err
	}
	if out == "" {
		return nil, nil
	}
	lines := strings.Split(out, "\n")
	entries := make([]LogEntry, 0, len(lines))
	for _, line := range lines {
		parts := strings.SplitN(line, "\t", 3)
		if len(parts) < 3 {
			continue
		}
		entries = append(entries, LogEntry{
			Hash:    parts[0],
			Subject: parts[1],
			Age:     shortenAge(parts[2]),
		})
	}
	return entries, nil
}

// DiffStats summarises a diff between base and HEAD.
type DiffStats struct {
	Commits   int
	Files     int
	Additions int
	Deletions int
}

// DiffStatsIn returns commits-ahead and shortstat (files/additions/deletions)
// for HEAD vs base. Empty range yields zeroed struct, not an error.
func DiffStatsIn(dir, base string) (DiffStats, error) {
	stats := DiffStats{}

	commitsStr, err := RunIn(dir, "rev-list", "--count", base+"..HEAD")
	if err != nil {
		return stats, err
	}
	stats.Commits, _ = strconv.Atoi(strings.TrimSpace(commitsStr))

	if stats.Commits == 0 {
		return stats, nil
	}

	// `git diff --shortstat` output: " 14 files changed, 247 insertions(+), 82 deletions(-)"
	shortstat, err := RunIn(dir, "diff", "--shortstat", base+"..HEAD")
	if err != nil {
		return stats, err
	}
	stats.Files, stats.Additions, stats.Deletions = parseShortstat(shortstat)
	return stats, nil
}

func parseShortstat(s string) (files, adds, dels int) {
	for part := range strings.SplitSeq(s, ",") {
		part = strings.TrimSpace(part)
		fields := strings.Fields(part)
		if len(fields) < 2 {
			continue
		}
		n, err := strconv.Atoi(fields[0])
		if err != nil {
			continue
		}
		switch {
		case strings.HasPrefix(fields[1], "file"):
			files = n
		case strings.HasPrefix(fields[1], "insertion"):
			adds = n
		case strings.HasPrefix(fields[1], "deletion"):
			dels = n
		}
	}
	return
}

// DiffFile is one entry from `git diff --name-status`.
type DiffFile struct {
	Status string // "M", "A", "D", "R", "C", "T", etc.
	Path   string
}

// CommitDetail is the full info shown for one commit in the dashboard's
// commit-detail panel.
type CommitDetail struct {
	Hash    string
	Author  string
	Email   string
	Date    string // ISO-8601 from %ai, already formatted
	Subject string
	Body    string
	Files   []CommitFile
}

// CommitFile is one file changed by a commit, with line counts.
// Status is derived from the numstat counts:
//
//	A (added)    when Dels == 0 && Adds > 0
//	D (deleted)  when Adds == 0 && Dels > 0
//	M (modified) when both are non-zero
//	B (binary)   when numstat reports "-" for either
type CommitFile struct {
	Status string
	Path   string
	Adds   int
	Dels   int
}

// CommitDetailIn fetches the metadata and per-file change list for a commit.
// Two git calls — both fast — combined into a single struct.
func CommitDetailIn(dir, hash string) (CommitDetail, error) {
	var d CommitDetail

	// Metadata: null-separated to survive any character that might appear in
	// subject/body (newlines, tabs, unicode, etc.).
	metaOut, err := RunIn(dir, "show", "-s",
		"--format=%H%x00%an%x00%ae%x00%ai%x00%s%x00%b", hash)
	if err != nil {
		return d, err
	}
	parts := strings.SplitN(metaOut, "\x00", 6)
	if len(parts) < 6 {
		return d, fmt.Errorf("unexpected git show output for %s", hash)
	}
	d.Hash = parts[0]
	d.Author = parts[1]
	d.Email = parts[2]
	d.Date = parts[3]
	d.Subject = parts[4]
	d.Body = strings.TrimSpace(parts[5])

	// Per-file changes via numstat.
	numOut, err := RunIn(dir, "show", "--numstat", "--format=", hash)
	if err != nil {
		// Metadata is still useful; return what we have.
		return d, nil
	}
	for line := range strings.SplitSeq(numOut, "\n") {
		fields := strings.Fields(line)
		if len(fields) < 3 {
			continue
		}
		addsStr, delsStr := fields[0], fields[1]
		path := fields[len(fields)-1]

		f := CommitFile{Path: path}
		switch {
		case addsStr == "-" || delsStr == "-":
			f.Status = "B"
		default:
			f.Adds, _ = strconv.Atoi(addsStr)
			f.Dels, _ = strconv.Atoi(delsStr)
			switch {
			case f.Adds > 0 && f.Dels == 0:
				f.Status = "A"
			case f.Adds == 0 && f.Dels > 0:
				f.Status = "D"
			default:
				f.Status = "M"
			}
		}
		d.Files = append(d.Files, f)
	}

	return d, nil
}

// DiffFilesIn returns per-file change status between base and HEAD.
func DiffFilesIn(dir, base string) ([]DiffFile, error) {
	out, err := RunIn(dir, "diff", "--name-status", base+"..HEAD")
	if err != nil {
		return nil, err
	}
	if out == "" {
		return nil, nil
	}
	lines := strings.Split(out, "\n")
	changes := make([]DiffFile, 0, len(lines))
	for _, line := range lines {
		fields := strings.Fields(line)
		if len(fields) < 2 {
			continue
		}
		// Rename/copy entries have an extra "score" suffix on the status (e.g. "R100")
		// and a second path; we only surface the first letter and the destination path.
		status := string(fields[0][0])
		path := fields[len(fields)-1]
		changes = append(changes, DiffFile{Status: status, Path: path})
	}
	return changes, nil
}

package cmd

import (
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/mvwi/wt/internal/git"
	"github.com/mvwi/wt/internal/github"
	"github.com/mvwi/wt/internal/ui"
	"github.com/mvwi/wt/internal/update"
	"github.com/spf13/cobra"
)

// errSilent is returned when the error has already been printed and
// Execute should exit non-zero without printing anything extra.
var errSilent = errors.New("")

// cwdOverride is set by the persistent -C/--directory flag and applied
// in PersistentPreRunE before any subcommand reads cwd.
var cwdOverride string

// Version is set at build time via -ldflags.
var Version = "dev"

var rootCmd = &cobra.Command{
	Use:   "wt",
	Short: "Git worktree manager",
	Long: `wt - Git Worktree Manager

A streamlined workflow for managing git worktrees. Create feature branches,
sync with your base branch, track PR status, and clean up when done.

Typical workflow:
  wt new feature        Create worktree + branch
  wt init               Initialize worktree (see .wt.toml)
  ...work on feature...
  wt submit             Rebase on base branch + push
  ...merge PR...
  wt prune              Clean up merged worktrees

Configuration:
  Global:    ~/.config/wt/config.toml
  Per-repo:  .wt.toml in repo root`,
	SilenceUsage:              true,
	SilenceErrors:             true,
	SuggestionsMinimumDistance: 2,
	Version:                   Version,
	RunE:                      runStatus,
}

// Command group IDs
const (
	groupWorkflow = "workflow"
	groupSync     = "sync"
	groupManage   = "manage"
)

// Execute runs the root command.
func Execute() {
	update.CheckInBackground()

	if err := rootCmd.Execute(); err != nil {
		if !errors.Is(err, errSilent) {
			// Cobra includes "Did you mean this?" in the error message
			// when SuggestionsMinimumDistance is set. Since we silence
			// errors to control output, we print the error ourselves.
			fmt.Fprintf(os.Stderr, "%s %s\n", ui.Red(ui.Fail), err)
		}
		os.Exit(1)
	}

	// Suppress update banner for shell-infrastructure commands that run
	// during shell init (their stderr is visible even though stdout is piped).
	if !isShellInitCommand() {
		if info := update.GetUpdateInfo(Version); info != nil {
			fmt.Fprintf(os.Stderr, "\n%s %s → %s\n",
				ui.Cyan(ui.PushUp+" Update available:"),
				ui.Dim(info.Current),
				ui.Cyan(info.Latest),
			)
			fmt.Fprintf(os.Stderr, "  %s\n", ui.Dim("brew upgrade wt"))
		}
	}
}

func init() {
	rootCmd.SetVersionTemplate("wt version {{.Version}}\n")
	rootCmd.CompletionOptions.HiddenDefaultCmd = true
	rootCmd.PersistentFlags().BoolVarP(&ui.YesFlag, "yes", "y", false, "skip confirmation prompts (answer yes to all)")
	rootCmd.PersistentFlags().StringVarP(&cwdOverride, "directory", "C", "", "run as if started in the given directory (like `git -C`)")
	_ = rootCmd.MarkPersistentFlagDirname("directory")

	rootCmd.PersistentPreRunE = applyCwdOverride

	rootCmd.AddGroup(
		&cobra.Group{ID: groupWorkflow, Title: "Workflow:"},
		&cobra.Group{ID: groupSync, Title: "Sync:"},
		&cobra.Group{ID: groupManage, Title: "Manage:"},
	)
}

// applyCwdOverride chdir's into the path passed via -C/--directory before any
// subcommand runs. All commands read cwd via os.Getwd() and run git from there,
// so a single chdir at startup propagates transparently to every command.
func applyCwdOverride(_ *cobra.Command, _ []string) error {
	if cwdOverride == "" {
		return nil
	}
	abs, err := filepath.Abs(cwdOverride)
	if err != nil {
		return fmt.Errorf("invalid directory %q: %w", cwdOverride, err)
	}
	if err := os.Chdir(abs); err != nil {
		return fmt.Errorf("cannot change to %s: %w", abs, err)
	}
	return nil
}

// isShellInitCommand returns true for commands that run during shell startup
// (init-shell, completion) where stderr output would be disruptive.
func isShellInitCommand() bool {
	if len(os.Args) < 2 {
		return false
	}
	switch os.Args[1] {
	case "init-shell", "completion":
		return true
	}
	return false
}

// runStatus is called when `wt` is run with no subcommand.
// Shows a quick status of the current worktree, or help if not in a repo.
func runStatus(cmd *cobra.Command, args []string) error {
	if !git.IsInsideWorkTree() {
		return cmd.Help()
	}

	ctx, err := newContext()
	if err != nil {
		return cmd.Help()
	}

	cwd, err := os.Getwd()
	if err != nil {
		return fmt.Errorf("cannot determine current directory: %w", err)
	}
	branch, err := git.CurrentBranch()
	if err != nil {
		return cmd.Help()
	}

	// Worktree name
	short := ctx.shortName(cwd)
	isMain := cwd == ctx.MainWorktree || isSubpath(cwd, ctx.MainWorktree)

	fmt.Printf("%s %s", ui.Yellow(ui.Current), short)
	if branch != short {
		fmt.Printf("  %s", ui.Dim(branch))
	}
	fmt.Println()

	// Base/main branch: just show it
	if isMain || ctx.isBaseBranch(branch) {
		return nil
	}

	// Sync status
	ab, err := git.GetAheadBehind(ctx.baseRef())
	if err == nil {
		var parts []string
		if ab.Behind > 0 {
			parts = append(parts, ui.Yellow(fmt.Sprintf("%s%d behind %s", ui.ArrowDown, ab.Behind, ctx.Config.BaseBranch)))
		}
		if ab.Ahead > 0 {
			parts = append(parts, ui.Green(fmt.Sprintf("%s%d ahead", ui.ArrowUp, ab.Ahead)))
		}
		if len(parts) > 0 {
			fmt.Printf("  %s\n", strings.Join(parts, "  "))
		} else {
			fmt.Printf("  %s\n", ui.Green("up to date with "+ctx.Config.BaseBranch))
		}
	}

	// Uncommitted changes
	if git.HasChanges() {
		statusShort, _ := git.StatusShort()
		lines := strings.Split(strings.TrimSpace(statusShort), "\n")
		fmt.Printf("  %s\n", ui.Yellow(fmt.Sprintf("%d uncommitted change(s)", len(lines))))
	}

	// Unpushed commits
	unpushed := git.UnpushedCountIn(cwd)
	if unpushed > 0 {
		fmt.Printf("  %s\n", ui.Cyan(fmt.Sprintf("%s%d unpushed commit(s)", ui.PushUp, unpushed)))
	}

	// PR status
	if github.IsAvailable() {
		pr, _ := github.GetPRForBranch(branch)
		if pr != nil && pr.State == "OPEN" {
			rs := pr.GetReviewSummary()
			cs := pr.GetCISummary()

			prStr := fmt.Sprintf("PR #%d", pr.Number)
			var details []string
			if rs.Approved > 0 {
				details = append(details, fmt.Sprintf("%d approved", rs.Approved))
			}
			if rs.Changes > 0 {
				details = append(details, fmt.Sprintf("%d changes requested", rs.Changes))
			}
			if rs.Pending > 0 {
				details = append(details, fmt.Sprintf("%d pending", rs.Pending))
			}
			switch {
			case cs.Fail > 0:
				details = append(details, ui.Red("CI failing"))
			case cs.Pending > 0:
				details = append(details, ui.Yellow("CI pending"))
			case cs.Pass > 0:
				details = append(details, ui.Green("CI passing"))
			}

			if len(details) > 0 {
				fmt.Printf("  %s  %s\n", ui.Blue(prStr), strings.Join(details, ", "))
			} else {
				fmt.Printf("  %s\n", ui.Blue(prStr))
			}
		}
	}

	return nil
}

