// Column widths.
const (
	colBranch = 28
	colAge    = 4
	colDirty  = 4
	colSync   = 8
	colPR     = 6
	colReview = 8
	colCI     = 8
)

func (m dashModel) View() string {
	var b strings.Builder

	nameWidth := 8
	for _, it := range m.items {
		nameWidth = max(nameWidth, lipgloss.Width(it.ShortName))
	}

	ruleWidth := nameWidth + 2 + colBranch + 1 + colAge + 1 + colDirty + 1 + colSync + 1 + colPR + 1 + colReview + 1 + colCI

	// Header
	b.WriteString("\n")
	b.WriteString("  " + dStyleHeader.Render("WORKTREES") + "\n")
	b.WriteString("  " + dStyleDim.Render(strings.Repeat("─", ruleWidth)) + "\n")

	// Column headers
	header := fmt.Sprintf("    %-*s  %-*s %-*s %-*s %-*s %-*s %-*s %-*s",
		nameWidth, "Name",
		colBranch, "Branch",
		colAge, "Age",
		colDirty, "Dirty",
		colSync, "Sync",
		colPR, "PR",
		colReview, "Review",
		colCI, "CI",
	)
	b.WriteString(dStyleDim.Render(header) + "\n")

	// Rows
	for i, it := range m.items {
		b.WriteString(m.renderRow(it, i == m.cursor, nameWidth))
		b.WriteString("\n")
	}

	// Detail panel for the focused row
	if m.fetchDetail != nil {
		b.WriteString("  " + dStyleDim.Render(strings.Repeat("─", ruleWidth)) + "\n")
		b.WriteString(m.renderDetail(ruleWidth))
	}

	// Third panel: commit detail — only when commits pane is focused.
	if m.focus == focusCommits && m.fetchCommitDetail != nil {
		b.WriteString("  " + dStyleDim.Render(strings.Repeat("─", ruleWidth)) + "\n")
		b.WriteString(m.renderCommitDetail(ruleWidth))
	}

	// Footer
	b.WriteString("  " + dStyleDim.Render(strings.Repeat("─", ruleWidth)) + "\n")

	if m.confirm != confirmNone {
		b.WriteString("  " + renderConfirmPrompt(m) + "\n")
	} else {
		status := buildStatusLine(m)
		keys := dStyleDim.Render(footerKeys(m))
		b.WriteString("  " + keys)
		if status != "" {
			pad := max(2, ruleWidth-lipgloss.Width(keys)-lipgloss.Width(status))
			b.WriteString(strings.Repeat(" ", pad) + status)
		}
		b.WriteString("\n")
	}

	return b.String()
}

// renderConfirmPrompt renders the inline footer prompt shown while a
// confirmation is active. y/enter confirms; any other key cancels.
func renderConfirmPrompt(m dashModel) string {
	switch m.confirm {
	case confirmRebaseAll:
		// Find base branch name for the prompt — falls back to "base" if absent.
		base := "base"
		for _, it := range m.items {
			if it.IsBase {
				base = it.Branch
				if base == "" {
					base = it.ShortName
				}
				break
			}
		}
		n := m.countRebaseTargets()
		return fmt.Sprintf("%s %s   %s %s",
			dStyleBold.Render(fmt.Sprintf("Rebase %d worktrees onto %s?", n, base)),
			dStyleDim.Render("·"),
			dStyleGreen.Render("[y]es"),
			dStyleDim.Render("[n]o · any other key cancels"),
		)
	}
	return ""
}

// footerKeys returns the keybinding hints appropriate to the current focus.
// Enter zooms in, esc zooms out. `s` switches the worktree from any level.
func footerKeys(m dashModel) string {
	if m.focus == focusCommits {
		return "↑↓ move · esc back · s switch · q quit"
	}
	return "↑↓ move · enter commits · s switch · r rebase · R rebase all · p prune · q quit"
}

func buildStatusLine(m dashModel) string {
	if m.lastErr != nil {
		return dStyleRed.Render("refresh failed: " + truncate(m.lastErr.Error(), 30))
	}
	if m.refreshing {
		return dStyleDim.Render("refreshing…")
	}
	elapsed := time.Since(m.lastRefresh).Truncate(time.Second)
	return dStyleDim.Render(fmt.Sprintf("updated %s ago", elapsed))
}

func (m dashModel) renderRow(it DashItem, isCursor bool, nameWidth int) string {

func (m dashModel) renderRow(it DashItem, isCursor bool, nameWidth int) string {
	currentGlyph := "  "
	if it.IsCurrent {
		currentGlyph = dStyleCurrent.Render("● ")
	}
	cursorGlyph := "  "
	if isCursor {
		cursorGlyph = dStyleCursor.Render("▸ ")
	}

	short := truncate(it.ShortName, nameWidth)
	shortRendered := dStyleName.Render(fmt.Sprintf("%-*s", nameWidth, short))
	if it.StaleDimmed {
		shortRendered = dStyleDim.Render(fmt.Sprintf("%-*s", nameWidth, short))
	}

	branch := ""
	if it.Branch != it.ShortName {
		branch = it.Branch
	}
	branchRendered := dStyleBranch.Render(fmt.Sprintf("%-*s", colBranch, truncate(branch, colBranch)))

	age := fmt.Sprintf("%-*s", colAge, it.Age)
	// Recent commits get a green tint so fresh worktrees pop. Stale rows always
	// stay dim (StaleDimmed is set by the cmd layer based on the threshold).
	ageStyle := styleForAge(it.Age)
	if it.StaleDimmed {
		ageStyle = dStyleDim
	}
	ageRendered := ageStyle.Render(age)

	dirty := dStyleDim.Render(fmt.Sprintf("%-*s", colDirty, "—"))
	if it.DirtyCount > 0 {
		dirty = dStyleYellow.Render(fmt.Sprintf("%-*d", colDirty, it.DirtyCount))
	}

	sync := buildSync(it)
	syncRendered := padAnsi(sync, colSync)

	var tail string
	tailWidth := colPR + 1 + colReview + 1 + colCI
	switch {
	case m.prunes[it.Path] != nil:
		tail = renderPruneCell(m.prunes[it.Path], tailWidth)
	case m.rebases[it.Path] != nil:
		tail = renderRebaseCell(m.rebases[it.Path], tailWidth)
	default:
		pr, review, ci := buildPRCells(it)
		tail = padAnsi(pr, colPR) + " " + padAnsi(review, colReview) + " " + padAnsi(ci, colCI)
	}

	row := fmt.Sprintf("%s%s%s  %s %s %s %s %s",
		cursorGlyph, currentGlyph, shortRendered, branchRendered,
		ageRendered, dirty, syncRendered, tail,
	)

	if isCursor {
		// Re-render the whole row with a background tint. Lipgloss will preserve
		// the inner foreground colors and just add a background.
		row = dStyleCursorRow.Render(row)
	}

	return "  " + row
}

// renderDetail renders the bottom panel for the focused worktree. Returns ""
// when there's no focus. Width is the rule width — content is wrapped/truncated
// to fit, but no minimum height is enforced.
func (m dashModel) renderDetail(width int) string {
	if m.cursor < 0 || m.cursor >= len(m.items) {
		return ""
	}
	it := m.items[m.cursor]

	var b strings.Builder

	// Title line: name · branch [· PR #N title]            @author
	title := dStyleName.Render(it.ShortName)
	if it.Branch != "" && it.Branch != it.ShortName {
		title += "  " + dStyleDim.Render("· "+it.Branch)
	}

	cache, hasCache := m.details[it.Path]

	if hasCache && cache.err == nil && it.PR != nil && cache.data.PRTitle != "" {
		// PR # in blue (consistent with the worktree table); title in bold default
		// so it reads as the headline.
		title += "  " + dStyleDim.Render("·") + " " +
			dStyleBlue.Render(fmt.Sprintf("PR #%d", it.PR.Number)) + "  " +
			dStyleBold.Render(cache.data.PRTitle)
	}

	titleLine := "  " + title
	if hasCache && cache.err == nil && cache.data.PRAuthor != "" {
		// Author handles in cyan — scannable metadata accent.
		author := dStyleCyan.Render("@" + cache.data.PRAuthor)
		pad := max(2, width-lipgloss.Width(titleLine)-lipgloss.Width(author)+2)
		titleLine += strings.Repeat(" ", pad) + author
	}
	b.WriteString(titleLine + "\n")

	if !hasCache {
		fmt.Fprintf(&b, "  %s\n", dStyleDim.Render("loading detail…"))
		return b.String()
	}
	if cache.err != nil {
		fmt.Fprintf(&b, "  %s\n", dStyleRed.Render("detail unavailable: "+truncate(cache.err.Error(), width-22)))
		return b.String()
	}

	d := cache.data

	// PR body (first paragraph, single line) — issue refs in blue, rest dim.
	if d.PRBody != "" {
		body := truncate(collapseWhitespace(d.PRBody), width-4)
		fmt.Fprintf(&b, "\n  %s\n", colorizeBody(body))
	}

	// CHANGES line
	if d.Stats.Commits > 0 || d.Stats.Files > 0 {
		fmt.Fprintf(&b, "\n  %s   %s\n",
			dStyleSection.Render("CHANGES"),
			buildStatsLine(d.Stats),
		)
	}

	// COMMITS section (with focus-aware cursor)
	if len(d.Commits) > 0 {
		header := "COMMITS"
		if m.focus == focusCommits {
			header += dStyleDim.Render("  ▸ j/k navigate · esc back")
		}
		fmt.Fprintf(&b, "\n  %s\n", dStyleSection.Render(header))
		typeWidth := commitTypeWidth(d.Commits)
		ageWidth := commitAgeWidth(d.Commits)
		subjectWidth := max(20, width-4-2-typeWidth-1-1-ageWidth)
		for i, c := range d.Commits {
			b.WriteString(m.renderCommitRow(c, i, typeWidth, subjectWidth, ageWidth))
			b.WriteString("\n")
		}
	}

	// FILES line
	if len(d.Files) > 0 {
		fmt.Fprintf(&b, "\n  %s     %s\n",
			dStyleSection.Render("FILES"),
			buildFilesLine(d.Files, width-12),
		)
	}

	// CI line
	if len(d.Checks) > 0 {
		fmt.Fprintf(&b, "  %s        %s\n",
			dStyleSection.Render("CI"),
			buildChecksLine(d.Checks, width-12),
		)
	}

	return b.String()
}

// renderCommitDetail renders the third panel — the full detail for the commit
// under the commit cursor when the commits pane is focused.
func (m dashModel) renderCommitDetail(width int) string {
	commits := m.focusedCommits()
	if m.commitCursor < 0 || m.commitCursor >= len(commits) {
		return ""
	}
	hash := commits[m.commitCursor].Hash
	cache, hasCache := m.commitDetails[hash]

	var b strings.Builder

	// COMMIT section — subject (with conventional-commit color), then author/date,
	// then wrapped body.
	if !hasCache {
		fmt.Fprintf(&b, "  %s    %s\n",
			dStyleSection.Render("COMMIT"),
			dStyleDim.Render("loading…"),
		)
		return b.String()
	}
	if cache.err != nil {
		fmt.Fprintf(&b, "  %s    %s\n",
			dStyleSection.Render("COMMIT"),
			dStyleRed.Render("error: "+truncate(cache.err.Error(), width-20)),
		)
		return b.String()
	}

	d := cache.data
	const labelCol = 12 // "COMMIT    " + indent
	contentWidth := max(20, width-labelCol)

	// Render subject with conventional-commit type colored.
	typeCell, subjectRest := formatCommitType(d.Subject, 0)
	subjectRendered := strings.TrimSpace(typeCell) + " " + subjectRest
	if strings.TrimSpace(typeCell) == "" {
		subjectRendered = subjectRest
	}
	fmt.Fprintf(&b, "  %s    %s\n",
		dStyleSection.Render("COMMIT"),
		truncate(subjectRendered, contentWidth),
	)

