func (m dashModel) renderRow(it DashItem, isCursor bool, nameWidth int) string {
	currentGlyph := "  "
	if it.IsCurrent {
		currentGlyph = dStyleCurrent.Render("● ")
	}
	cursorGlyph := "  "
	if isCursor {
		cursorGlyph = dStyleCursor.Render("▸ ")
	}

	short := truncate(it.ShortName, nameWidth)
	shortRendered := dStyleName.Render(fmt.Sprintf("%-*s", nameWidth, short))
	if it.StaleDimmed {
		shortRendered = dStyleDim.Render(fmt.Sprintf("%-*s", nameWidth, short))
	}

	branch := ""
	if it.Branch != it.ShortName {
		branch = it.Branch
	}
	branchRendered := dStyleBranch.Render(fmt.Sprintf("%-*s", colBranch, truncate(branch, colBranch)))

	age := fmt.Sprintf("%-*s", colAge, it.Age)
	// Recent commits get a green tint so fresh worktrees pop. Stale rows always
	// stay dim (StaleDimmed is set by the cmd layer based on the threshold).
	ageStyle := styleForAge(it.Age)
	if it.StaleDimmed {
		ageStyle = dStyleDim
	}
	ageRendered := ageStyle.Render(age)

	dirty := dStyleDim.Render(fmt.Sprintf("%-*s", colDirty, "—"))
	if it.DirtyCount > 0 {
		dirty = dStyleYellow.Render(fmt.Sprintf("%-*d", colDirty, it.DirtyCount))
	}

	sync := buildSync(it)
	syncRendered := padAnsi(sync, colSync)

	var tail string
	tailWidth := colPR + 1 + colReview + 1 + colCI
	switch {
	case m.prunes[it.Path] != nil:
		tail = renderPruneCell(m.prunes[it.Path], tailWidth)
	case m.rebases[it.Path] != nil:
		tail = renderRebaseCell(m.rebases[it.Path], tailWidth)
	default:
		pr, review, ci := buildPRCells(it)
		tail = padAnsi(pr, colPR) + " " + padAnsi(review, colReview) + " " + padAnsi(ci, colCI)
	}

	row := fmt.Sprintf("%s%s%s  %s %s %s %s %s",
		cursorGlyph, currentGlyph, shortRendered, branchRendered,
		ageRendered, dirty, syncRendered, tail,
	)

