// y/enter confirms; n/esc/any-other-key cancels.
func (m dashModel) handleConfirmKey(key string) (tea.Model, tea.Cmd) {
	switch key {
	case "y", "Y", "enter":
		kind := m.confirm
		m.confirm = confirmNone
		switch kind {
		case confirmRebaseAll:
			return m.executeRebaseAll()
		}
		return m, nil
	default:
		m.confirm = confirmNone
		return m, nil
	}
}

