)

func main() {
	// We compile a small test that exercises the layout function directly via
	// reflection-by-output. Easier: just print a matrix from the binary via a
	// hidden flag. Since we don't have one, this file just documents expected
	// shapes. Use it as a manual checklist.
	fmt.Println("compute manually:")

	widths := []int{50, 60, 68, 76, 80, 100, 140, 200}
	for _, w := range widths {
		fmt.Printf("  termWidth=%3d → %s\n", w, expected(w))
	}
	_ = exec.Command
}

func expected(termWidth int) string {
	nameW := 8
	avail := termWidth - 2
	fixedFull := 2 + 2 + nameW + 2 + 1 + 4 + 1 + 4 + 1 + 8 + 1 + (6 + 1 + 8 + 1 + 8) // 58
	fixedNarrow := 2 + 2 + nameW + 2 + 1 + 4 + 1 + 4 + 1 + 8 + 1 + 16                // 50
	min := 16
	max := 64

	if avail >= fixedFull+min {
		bw := avail - fixedFull
		if bw > max {
			bw = max
		}
		return fmt.Sprintf("full  branch=%d  content=%d", bw, 2+fixedFull+bw)
	}
	if avail >= fixedNarrow+min {
		bw := avail - fixedNarrow
		if bw > max {
			bw = max
		}
		return fmt.Sprintf("narrow branch=%d  content=%d", bw, 2+fixedNarrow+bw)
	}
	return "tiny (resize hint)"
}

