	}
	// Count eligible worktrees to give the user concrete numbers.
	if m.countRebaseTargets() == 0 {
		return m, nil
	}
	m.confirm = confirmRebaseAll
	return m, nil
}

// executeRebaseAll dispatches a rebase for every non-base worktree concurrently.
// Each rebase runs in its own goroutine via dashRebaseCmd; results arrive as
// dashRebaseDoneMsg and are rendered per-row.
func (m dashModel) executeRebaseAll() (tea.Model, tea.Cmd) {
	var cmds []tea.Cmd
	for _, it := range m.items {
		if it.IsBase {
			continue
		}
		if _, busy := m.rebases[it.Path]; busy {
			continue
		}
		if _, pruning := m.prunes[it.Path]; pruning {
			continue
		}
		m.rebases[it.Path] = &dashRebaseState{phase: "running"}
		cmds = append(cmds, dashRebaseCmd(m.rebase, it.Path, it.Branch))
	}
	if len(cmds) == 0 {
		return m, nil
	}
	return m, tea.Batch(cmds...)
}

// countRebaseTargets returns how many worktrees would be touched by `R`.
func (m dashModel) countRebaseTargets() int {
	n := 0
	for _, it := range m.items {
		if it.IsBase {
			continue
		}
		if _, busy := m.rebases[it.Path]; busy {
			continue
		}
		if _, pruning := m.prunes[it.Path]; pruning {
			continue
		}
		n++
	}
	return n
}

// startPrune queues an async prune for the highlighted worktree. No-ops when
// the row isn't a valid prune target (no PR / PR still open / current / base /
// already pruning). Multiple concurrent prunes are supported.
func (m dashModel) startPrune() (tea.Model, tea.Cmd) {
	if m.prune == nil {
		return m, nil
	}
	if m.cursor < 0 || m.cursor >= len(m.items) {
		return m, nil
	}
	it := m.items[m.cursor]
	if !canPrune(it) {
		return m, nil
	}
	if _, busy := m.prunes[it.Path]; busy {
		return m, nil
	}
	m.prunes[it.Path] = &dashPruneState{phase: "pruning"}
	return m, dashPruneCmd(m.prune, it.Path, it.Branch)
}

// canPrune reports whether a row is eligible for in-dashboard pruning.
// Matches the eligibility rules of the standalone `wt prune` command:
// must have a merged or closed PR, not be the current worktree or a base branch.
func canPrune(it DashItem) bool {
	if it.IsBase || it.IsCurrent {
		return false
	}
	if it.PR == nil {
		return false
	}
	return it.PR.State == "merged" || it.PR.State == "closed"
}

