// renderPruneCell renders the ephemeral prune state that replaces the
// [pr][review][ci] columns while a prune is in flight or recently completed.
func renderPruneCell(p *dashPruneState, width int) string {
	var s string
	switch p.phase {
	case "pruning":
		s = dStyleYellow.Render("pruning…")
	case "done":
		s = dStyleGreen.Render("✓ pruned")
	case "failed":
		msg := p.errMsg
		if msg == "" {
			msg = "failed"
		}
		s = dStyleRed.Render("✗ " + truncate(msg, width-2))
	}
	return padAnsi(s, width)
}

